import { useEffect, useMemo, useState } from 'react'
import { motion } from 'framer-motion'
import { ensureAdminSession, getAdminState, commitAdminState } from '../adminStore'
import { Plus, Trash2 } from 'lucide-react'

export default function AdminCoupons() {
  const [code, setCode] = useState('')
  const [discountPct, setDiscountPct] = useState('10')
  const [expiry, setExpiry] = useState('')
  const [enabledOnly, setEnabledOnly] = useState(false)
  const [busy, setBusy] = useState(false)

  useEffect(() => {
    ensureAdminSession()
  }, [])

  const { data } = useMemo(() => getAdminState(), [busy])
  const coupons = data?.coupons || []

  const filtered = useMemo(() => {
    return enabledOnly ? coupons.filter((c) => c.enabled) : coupons
  }, [coupons, enabledOnly])

  const money = (n) => Number(n || 0).toLocaleString('en-IN')

  const createCoupon = () => {
    const c = code.trim().toUpperCase()
    if (!c) return
    setBusy(true)
    const next = structuredClone(data)
    next.coupons = next.coupons || []
    const exists = next.coupons.some((x) => x.code === c)
    if (!exists) {
      next.coupons.unshift({
        id: `cp_${c}_${Date.now()}`,
        code: c,
        enabled: true,
        discountPct: Number(discountPct || 0),
        expiry,
        createdAt: Date.now(),
      })
    }
    commitAdminState(next)
    setBusy(false)
    setCode('')
    setDiscountPct('10')
    setExpiry('')
  }

  const toggle = (id) => {
    setBusy(true)
    const next = structuredClone(data)
    next.coupons = next.coupons.map((c) => (c.id === id ? { ...c, enabled: !c.enabled } : c))
    commitAdminState(next)
    setBusy(false)
  }

  const del = (id) => {
    setBusy(true)
    const next = structuredClone(data)
    next.coupons = next.coupons.filter((c) => c.id !== id)
    commitAdminState(next)
    setBusy(false)
  }

  return (
    <div className="px-0 sm:px-0">
      <div className="flex items-center justify-between mb-4 flex-col sm:flex-row gap-3">
        <div>
          <h1 className="text-2xl font-bold text-white">Coupons</h1>
          <p className="text-gray-400 text-sm">Create and manage coupons with enable/disable and expiry.</p>
        </div>
        <div className="flex items-center gap-2">
          <label className="text-sm text-gray-300 flex items-center gap-2">
            <input type="checkbox" checked={enabledOnly} onChange={(e) => setEnabledOnly(e.target.checked)} />
            Enabled only
          </label>
        </div>
      </div>

      <div className="glass-dark rounded-2xl p-5 mb-4">
        <div className="flex items-start justify-between gap-3 flex-col md:flex-row">
          <div>
            <h2 className="text-lg font-bold text-white">Create Coupon</h2>
            <p className="text-gray-400 text-sm mt-1">Demo only: stored in localStorage.</p>
          </div>
          <button onClick={createCoupon} disabled={busy} className="amazon-btn-primary amazon-btn inline-flex items-center gap-2" type="button">
            <Plus size={16} /> {busy ? 'Saving...' : 'Create'}
          </button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mt-4">
          <div className="md:col-span-1">
            <label className="text-xs text-gray-400">Code</label>
            <input value={code} onChange={(e) => setCode(e.target.value)} className="w-full mt-2 bg-white/5 border border-white/10 rounded-xl px-3 py-2 text-sm outline-none" placeholder="SAVE10" />
          </div>
          <div>
            <label className="text-xs text-gray-400">Discount %</label>
            <input value={discountPct} onChange={(e) => setDiscountPct(e.target.value)} className="w-full mt-2 bg-white/5 border border-white/10 rounded-xl px-3 py-2 text-sm outline-none" />
          </div>
          <div className="md:col-span-1">
            <label className="text-xs text-gray-400">Expiry date</label>
            <input type="date" value={expiry} onChange={(e) => setExpiry(e.target.value)} className="w-full mt-2 bg-white/5 border border-white/10 rounded-xl px-3 py-2 text-sm outline-none" />
          </div>
        </div>
      </div>

      <motion.div className="glass-dark rounded-2xl p-5" initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
        <h2 className="text-lg font-bold text-white mb-3">Coupons Table</h2>

        <div className="overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr className="text-gray-400 text-xs border-b border-white/10">
                <th className="text-left py-3">Code</th>
                <th className="text-left py-3">Discount</th>
                <th className="text-left py-3">Expiry</th>
                <th className="text-left py-3">Status</th>
                <th className="text-left py-3">Actions</th>
              </tr>
            </thead>
            <tbody>
              {filtered.map((c) => (
                <tr key={c.id} className="border-b border-white/5">
                  <td className="py-3">
                    <div className="text-white font-semibold">{c.code}</div>
                    <div className="text-gray-400 text-xs font-mono">{c.id}</div>
                  </td>
                  <td className="py-3 text-gray-200">{c.discountPct}%</td>
                  <td className="py-3 text-gray-200">{c.expiry || '—'}</td>
                  <td className="py-3">
                    <button
                      onClick={() => toggle(c.id)}
                      className={c.enabled ? 'px-3 py-2 rounded-xl text-xs border border-green-500/20 bg-green-500/10 text-green-300' : 'px-3 py-2 rounded-xl text-xs border border-red-500/20 bg-red-500/10 text-red-300'}
                      type="button"
                      disabled={busy}
                    >
                      {c.enabled ? 'Enabled' : 'Disabled'}
                    </button>
                  </td>
                  <td className="py-3">
                    <button onClick={() => del(c.id)} disabled={busy} className="amazon-btn-danger amazon-btn inline-flex items-center gap-2" type="button">
                      <Trash2 size={16} /> Delete
                    </button>
                  </td>
                </tr>
              ))}
              {filtered.length === 0 && (
                <tr>
                  <td colSpan={5} className="py-12 text-center text-gray-400">No coupons found.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </motion.div>
    </div>
  )
}

