import { useEffect, useMemo, useState } from 'react'
import { useParams, useNavigate } from 'react-router-dom'
import { motion } from 'framer-motion'
import { Star, Check, Truck, Shield, Zap } from 'lucide-react'
import api from '../services/api'

const fallbackImageUrl = '/placeholder-speaker.jpg'

export default function ProductPage() {
  const { id } = useParams()
  const navigate = useNavigate()

  const [product, setProduct] = useState(null)
  const [loading, setLoading] = useState(false)

  const [selectedImage, setSelectedImage] = useState(0)
  const [selectedVariant, setSelectedVariant] = useState('Black')

  useEffect(() => {
    let cancelled = false

    const load = async () => {
      if (!id) return
      setLoading(true)
      try {
        const res = await api.get(`/products/${id}`)
        const p = res?.data
        if (cancelled) return

        if (p) {
          setProduct({
            id: p.id ?? p._id,
            name: p.name,
            offerPrice: p.price,
            price: p.price,
            discountPercentage: p.discountPct ?? 0,
            images: p.imageUrl ? [{ imageUrl: p.imageUrl }] : [],
            shortDescription: p.category,
            rating: 0,
            totalReviews: 0,
            specifications: {},
          })
        }
      } catch {
        if (!cancelled) setProduct(null)
      } finally {
        if (!cancelled) setLoading(false)
      }
    }

    load()
    return () => {
      cancelled = true
    }
  }, [id])



  const handleBuyNow = () => {
    navigate(`/buy/${id}`)
  }

  return (
    <div className="section-padding py-8">
      <div className="max-w-7xl mx-auto">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 lg:gap-12">
          {/* Image Gallery */}
          <motion.div initial={{ opacity: 0, x: -20 }} animate={{ opacity: 1, x: 0 }}>
            <div className="aspect-square rounded-3xl overflow-hidden bg-dark-card border border-dark-border mb-4">
              <img
                src={product.images[selectedImage]?.imageUrl}
                alt={product.name}
                className="w-full h-full object-cover"
              />
            </div>
            <div className="flex gap-3">
              {product.images.map((img, i) => (
                <button
                  key={i}
                  onClick={() => setSelectedImage(i)}
                  className={`w-20 h-20 rounded-xl overflow-hidden border-2 transition-all ${
                    selectedImage === i ? 'border-brand-500' : 'border-dark-border'
                  }`}
                >
                  <img src={img.imageUrl} alt="" className="w-full h-full object-cover" />
                </button>
              ))}
            </div>
          </motion.div>

          {/* Product Info */}
          <motion.div initial={{ opacity: 0, x: 20 }} animate={{ opacity: 1, x: 0 }} className="space-y-6">
            <div>
              <h1 className="text-3xl md:text-4xl font-bold text-white">{product.name}</h1>
              <div className="flex items-center gap-3 mt-3">
                <div className="flex items-center gap-1 bg-yellow-500/10 px-3 py-1 rounded-full">
                  <Star size={16} className="text-yellow-400 fill-yellow-400" />
                  <span className="text-yellow-400 font-semibold">{product.rating}</span>
                </div>
                <span className="text-gray-400">{product.totalReviews} Reviews</span>
              </div>
            </div>

            <p className="text-gray-400 text-lg">{product.shortDescription}</p>

            <div className="flex items-baseline gap-3">
              <span className="text-4xl font-bold text-white">₹{product.offerPrice}</span>
              {product.discountPercentage > 0 && (
                <>
                  <span className="text-xl text-gray-500 line-through">₹{product.price}</span>
                  <span className="text-green-400 font-semibold">{product.discountPercentage}% off</span>
                </>
              )}
            </div>

            {/* Variants */}
            <div>
              <label className="text-sm text-gray-400 mb-2 block">Color</label>
              <div className="flex gap-3">
                {['Black', 'Blue', 'Red'].map(color => (
                  <button
                    key={color}
                    onClick={() => setSelectedVariant(color)}
                    className={`px-4 py-2 rounded-xl border transition-all ${
                      selectedVariant === color
                        ? 'border-brand-500 bg-brand-500/10 text-brand-400'
                        : 'border-dark-border text-gray-400 hover:border-gray-600'
                    }`}
                  >
                    {color}
                  </button>
                ))}
              </div>
            </div>

            {/* Key Features */}
            <div className="grid grid-cols-2 gap-3">
              {[
                { icon: Zap, text: '40W Powerful Bass' },
                { icon: Shield, text: '2 Year Warranty' },
                { icon: Truck, text: 'Free Delivery' },
                { icon: Check, text: 'In Stock' },
              ].map((feature, i) => (
                <div key={i} className="flex items-center gap-2 p-3 bg-dark-card rounded-xl">
                  <feature.icon size={18} className="text-brand-400" />
                  <span className="text-sm text-gray-300">{feature.text}</span>
                </div>
              ))}
            </div>

            {/* Buy Now Button */}
            <button
              onClick={handleBuyNow}
              className="w-full py-4 text-lg font-bold animate-glow"
              style={{
                background: 'linear-gradient(to bottom, #FDCB5A, #F08804)',
                color: '#111827',
                boxShadow: '0 10px 30px rgba(240,136,4,0.35)',
                borderRadius: '12px',
              }}
            >
              Buy Now
            </button>

            {/* Specifications */}
            <div className="border-t border-dark-border pt-6">
              <h3 className="text-lg font-semibold text-white mb-4">Specifications</h3>
              <div className="space-y-3">
                {Object.entries(product.specifications).map(([key, value]) => (
                  <div key={key} className="flex justify-between py-2 border-b border-dark-border">
                    <span className="text-gray-400">{key}</span>
                    <span className="text-white font-medium">{value}</span>
                  </div>
                ))}
              </div>
            </div>
          </motion.div>
        </div>
      </div>
    </div>
  )
}

