import { useEffect, useMemo, useState } from 'react'
import { Link, useNavigate } from 'react-router-dom'
import {
  HelpCircle,
  MapPin,
  Menu,
  Search,
  Settings,
  Shield,
  ShoppingCart,
  Sparkles,
  UserRound,
  X,
} from 'lucide-react'
import { useDispatch, useSelector } from 'react-redux'
import { logout as logoutAction } from '../redux/slices/authSlice'

export default function Header() {
  const dispatch = useDispatch()
  const cartCount = useSelector((state) => state.cart.items?.length || 0)

  const [searchQuery, setSearchQuery] = useState('')
  const [isMenuOpen, setIsMenuOpen] = useState(false)
  const navigate = useNavigate()
  const { isAuthenticated, user, hydrated } = useSelector((state) => state.auth)

  const username = useMemo(() => {
    const firstName = user?.firstName
    const email = user?.email
    return firstName || email || 'User'
  }, [user])

  useEffect(() => {
    if (!isMenuOpen) return

    const prevOverflow = document.body.style.overflow
    document.body.style.overflow = 'hidden'

    return () => {
      document.body.style.overflow = prevOverflow
    }
  }, [isMenuOpen])

  const closeMenu = () => setIsMenuOpen(false)

  const handleLogout = () => {
    dispatch(logoutAction())

    // Ensure demo tokens/sessions are fully cleared.
    localStorage.removeItem('token')
    localStorage.removeItem('adminToken')
    localStorage.removeItem('role')
    localStorage.removeItem('user')

    closeMenu()
    navigate('/login', { replace: true })
  }



  const MenuItem = ({
    to,
    onClick,
    icon: Icon,
    title,
    subtitle,
    className = '',
    isActive = false,
  }) => {
    const content = (
      <div className="flex items-center gap-2">
        {Icon ? (
          <div className="h-8 w-8 rounded-xl bg-white/5 border border-white/10 flex items-center justify-center shadow-[0_0_20px_rgba(43,107,255,0.18)]">
            <Icon size={16} className="text-[#93C5FD]" />
          </div>
        ) : null}

        <div className="min-w-0">
          <div className="font-bold text-[12.5px] leading-tight text-white">{title}</div>
          {subtitle ? (
            <div className="text-[10.5px] text-white/60 leading-tight mt-0.5">{subtitle}</div>
          ) : null}
        </div>
      </div>
    )


    if (to) {
      return (
        <Link
          to={to}
          onClick={() => {
            closeMenu()
          }}
          className={`group ${
            'block w-full text-left rounded-2xl border border-white/10 bg-white/5 hover:bg-white/10 transition-colors px-4 py-3.5'}
            ${className}`
          }
        >
          {content}
        </Link>
      )
    }

    return (
      <button
        type="button"
        onClick={() => {
          if (onClick) onClick()
          else closeMenu()
        }}
        className={`group ${
          'w-full text-left rounded-2xl border border-white/10 bg-white/5 hover:bg-white/10 transition-colors px-4 py-3.5'}
          ${className}`
        }
      >
        {content}
      </button>
    )
  }

  const handleSearch = (e) => {
    e.preventDefault()
    if (searchQuery.trim()) {
      navigate(`/search?q=${encodeURIComponent(searchQuery)}`)
    }
  }

  return (
    <header className="sticky top-0 z-50">
      {/* Mobile drawer + overlay (mobile only) */}
      <div
        className={`md:hidden fixed inset-0 z-[60] pointer-events-none ${
          isMenuOpen ? 'pointer-events-auto' : ''
        }`}
        aria-hidden={!isMenuOpen}
      >
        {/* Overlay */}
        <div
          role="button"
          tabIndex={-1}
          className={`absolute inset-0 bg-black/60 backdrop-blur-sm transition-opacity duration-200 ${
            isMenuOpen ? 'opacity-100' : 'opacity-0'
          }`}
          onClick={() => closeMenu()}
        />

        {/* Drawer */}
        <aside
          className={`absolute left-0 top-0 h-full w-[300px] max-w-[84vw] bg-white/5 backdrop-blur-xl border-r border-white/10 shadow-[0_0_70px_rgba(43,107,255,0.25)] transition-transform duration-250 ease-out ${
            isMenuOpen ? 'translate-x-0' : '-translate-x-full'
          }`}
        >
          <div className="p-3.5">
            {/* Close button */}
            <div className="flex items-center justify-between">
              <div className="inline-flex items-center gap-2">
                <div className="h-9 w-9 rounded-xl bg-[#2B6BFF]/15 border border-[#2B6BFF]/30 flex items-center justify-center shadow-[0_0_26px_rgba(43,107,255,0.18)]">
                  <Sparkles size={16} className="text-[#93C5FD]" />
                </div>
                <div>
                  <div className="text-white font-extrabold text-[13px] leading-tight">WebSpeak</div>
                  <div className="text-white/60 text-[10.5px] leading-tight">Premium Audio</div>
                </div>
              </div>


              <button
                type="button"
                onClick={() => closeMenu()}
                aria-label="Close menu"
                className="inline-flex items-center justify-center p-2 rounded-xl hover:bg-white/10 active:scale-[0.98]"
              >
                <X size={20} className="text-white" />
              </button>
            </div>

            {/* Profile */}
              <div className="mt-3 rounded-2xl bg-[#0B1220]/35 border border-white/10 p-3">
                <div className="flex items-center gap-2">
                  <div className="h-9 w-9 rounded-xl bg-white/5 border border-white/10 flex items-center justify-center shadow-[0_0_24px_rgba(43,107,255,0.18)]">
                    <UserRound size={16} className="text-[#93C5FD]" />
                  </div>
                  <div className="min-w-0">
                    <div className="text-[12.5px] font-bold text-white truncate">Hello, {username}</div>
                    <div className="text-[11px] text-white/70 truncate">
                      {isAuthenticated ? user?.email || user?.firstName || 'Account' : 'Sign in for order updates'}
                    </div>
                  </div>
                </div>

                <div className="mt-2 grid grid-cols-2 gap-1.5">
                  <MenuItem
                    to="/profile"
                    title="Profile"
                    icon={UserRound}
                    className="p-0"
                  />
                  <MenuItem
                    to="/orders"
                    title="Orders"
                    icon={Shield}
                    className="p-0"
                  />
                </div>
              </div>


            {/* Orders section */}
            <div className="mt-3">
              <div className="text-[#93C5FD] font-extrabold text-[11px] tracking-wide px-2">ORDERS</div>
              <div className="mt-2 space-y-1.5">
                <MenuItem to="/orders" title="My Orders" icon={Sparkles} />
                <MenuItem to="/orders/pending" title="Pending" icon={Shield} />
                <MenuItem to="/orders/delivered" title="Delivered" icon={Sparkles} />
                <MenuItem to="/orders/cancelled" title="Cancelled" icon={Settings} />
                <MenuItem to="/returns" title="Returns" icon={HelpCircle} />
              </div>
            </div>

            {/* Main navigation */}
            <div className="mt-3">
              <div className="text-[#93C5FD] font-extrabold text-[11px] tracking-wide px-2">MENU</div>
              <div className="mt-2 space-y-1.5">
                <MenuItem to="/wishlist" title="Wishlist" icon={Shield} />
                <MenuItem to="/cart" title="Cart" icon={ShoppingCart} />
                <MenuItem to="/profile" title="Notifications" icon={HelpCircle} />
                <MenuItem to="/settings" title="Settings" icon={Settings} />
                <MenuItem to="/returns" title="Help & Support" icon={HelpCircle} />
              </div>
            </div>

            {/* Logout */}
            <div className="mt-3">
              <MenuItem
                to={null}
                title="Logout"
                icon={X}
                className="border-[#FEBD69]/40 hover:bg-[#FEBD69]/10"
                onClick={handleLogout}
              />
            </div>

          </div>
        </aside>
      </div>

      <div className="bg-[#131921] text-white">

        {/* Top compact navbar */}
        <div className="flex items-center gap-2 px-3 py-2 h-[56px]">
          {/* Mobile hamburger */}
          <button
            type="button"
            className="md:hidden inline-flex items-center justify-center p-2 rounded-md hover:bg-white/5 active:scale-[0.98]"
            aria-label="Open menu"
            onClick={() => setIsMenuOpen(true)}
          >
            <Menu size={20} />
          </button>


          <Link to="/" className="shrink-0 hover:opacity-80">
            <div className="flex flex-col leading-tight">
              <span className="text-xl md:text-2xl font-bold">WebSpeak</span>
              <span className="text-[10px] text-gray-300">Premium Audio</span>
            </div>
          </Link>

          <div className="hidden md:flex items-center gap-1 hover:outline hover:outline-1 hover:outline-white rounded-sm px-2 py-1 cursor-pointer ml-2 shrink-0">
            <MapPin size={16} className="mt-1" />
            <div className="text-xs leading-tight">
              <div className="text-gray-300">Deliver to</div>
              <div className="font-bold">Bangalore</div>
            </div>
          </div>

          {/* Desktop search stays inline */}
          <form
            onSubmit={handleSearch}
            className="hidden md:flex flex-1 flex mx-2 md:mx-4 max-w-2xl"
          >
            <button
              type="button"
              className="bg-gray-100 text-gray-700 px-2 rounded-l-md border-r border-gray-300 text-xs hover:bg-gray-200 shrink-0"
            >
              All
            </button>
            <input
              type="text"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              placeholder="Search speakers..."
              className="flex-1 px-3 py-2 text-gray-900 text-sm focus:outline-none min-w-0"
            />
            <button
              type="submit"
              className="bg-[#FEBD69] hover:bg-[#F3A847] px-4 rounded-r-md shrink-0"
            >
              <Search size={20} className="text-gray-900" />
            </button>
          </form>

          <div className="flex items-center gap-1 shrink-0">
            {/* Desktop account */}
            <Link
              to={isAuthenticated ? '/dashboard' : '/login'}
              className="hidden lg:flex hover:outline hover:outline-1 hover:outline-white rounded-sm px-2 py-1 text-xs leading-tight"
              onClick={(e) => {
                if (!isAuthenticated && !user && !hydrated) {
                  e.preventDefault()
                }
              }}
            >
              <div className="text-gray-300">Hello, {isAuthenticated ? user?.firstName || 'User' : hydrated ? 'sign in' : '...'}</div>
              <div className="font-bold text-sm">Account</div>
            </Link>

            <Link
              to="/dashboard"
              className="hidden md:block hover:outline hover:outline-1 hover:outline-white rounded-sm px-2 py-1 text-xs leading-tight"
            >
              <div className="text-gray-300">Returns</div>
              <div className="font-bold text-sm">Orders</div>
            </Link>

            {/* Cart icon right */}
            <Link
              to="/buy/1"
              className="flex items-center justify-center hover:outline hover:outline-1 hover:outline-white rounded-sm px-2 py-1"
            >
              <div className="relative">
                <ShoppingCart size={28} />
                <span className="absolute -top-1 -right-1 bg-[#F08804] text-[#131921] text-xs font-bold rounded-full w-5 h-5 flex items-center justify-center">
                  {cartCount}
                </span>
              </div>
            </Link>
          </div>
        </div>

        {/* Mobile full-width search below navbar */}
        <form
          onSubmit={handleSearch}
          className="md:hidden px-3 pb-2"
        >
          <div className="flex items-center bg-white rounded-lg overflow-hidden shadow-sm">
            <button
              type="button"
              className="bg-gray-100 text-gray-700 px-3 py-2 text-xs font-semibold shrink-0 border-r border-gray-200"
            >
              All
            </button>
            <input
              type="text"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              placeholder="Search speakers..."
              className="flex-1 px-3 py-2 text-gray-900 text-sm focus:outline-none min-w-0"
            />
            <button
              type="submit"
              className="bg-[#FEBD69] hover:bg-[#F3A847] px-4 py-2 shrink-0"
            >
              <Search size={20} className="text-gray-900" />
            </button>
          </div>
        </form>

        {/* Category chips (mobile-friendly) */}
        <nav className="bg-[#232F3E] text-white text-sm px-3 py-2">
          <div className="flex items-center gap-2 overflow-x-auto [-ms-overflow-style:none] [scrollbar-width:none] [&::-webkit-scrollbar]:hidden">
            <Link
              to="/search?q=all"
              className="whitespace-nowrap px-3 py-1 rounded-full border border-white/10 bg-white/0 hover:bg-white/10 active:bg-white/15 transition-colors"
            >
              <span className="inline-flex items-center gap-1">
                <Menu size={16} /> All
              </span>
            </Link>
            <Link
              to="/search?q=bluetooth"
              className="whitespace-nowrap px-3 py-1 rounded-full border border-white/10 bg-white/0 hover:bg-white/10"
            >
              Bluetooth
            </Link>
            <Link
              to="/search?q=party"
              className="whitespace-nowrap px-3 py-1 rounded-full border border-white/10 bg-white/0 hover:bg-white/10"
            >
              Party
            </Link>
            <Link
              to="/search?q=home"
              className="whitespace-nowrap px-3 py-1 rounded-full border border-white/10 bg-white/0 hover:bg-white/10"
            >
              Home Audio
            </Link>



            <div className="flex-1" />
            <span className="hidden lg:block text-[#FEBD69] font-bold whitespace-nowrap">
              Free Shipping on First Order!
            </span>
          </div>
        </nav>
      </div>
    </header>
  )
}


