import { useEffect, useMemo, useState } from 'react'
import { NavLink, Outlet, useLocation, useNavigate } from 'react-router-dom'
import { AnimatePresence, motion } from 'framer-motion'
import {
  LayoutDashboard,
  Package,
  Users,
  ShoppingBag,
  BarChart3,
  Ticket,
  Image as ImageIcon,
  Settings,
  LogOut,
  ChevronLeft,
  ChevronRight,
} from 'lucide-react'
import { ADMIN_ROUTES } from '../adminRoutes'

const sidebarItems = [
  { to: '/admin/dashboard', label: 'Dashboard', icon: LayoutDashboard },
  { to: '/admin/orders', label: 'Orders', icon: ShoppingBag },
  { to: '/admin/products', label: 'Products', icon: Package },
  { to: '/admin/users', label: 'Users', icon: Users },
  { to: '/admin/analytics', label: 'Analytics', icon: BarChart3 },
  { to: '/admin/coupons', label: 'Coupons', icon: Ticket },
  { to: '/admin/banners', label: 'Banners', icon: ImageIcon },
  { to: '/admin/settings', label: 'Settings', icon: Settings },
]

function logoutAdmin() {
  localStorage.removeItem('adminToken')
  localStorage.removeItem('role')
}

export default function AdminShell() {
  const [collapsed, setCollapsed] = useState(false)
  const navigate = useNavigate()
  const location = useLocation()

  const title = useMemo(() => {
    const hit = sidebarItems.find((x) => x.to === location.pathname)
    return hit?.label || 'Admin'
  }, [location.pathname])

  useEffect(() => {
    // If user lands directly on /admin/* root (without route), keep sidebar expanded state stable.
  }, [])

  return (
    <div className="min-h-screen bg-[#070A12] text-white">
      <div className="sticky top-0 z-30 backdrop-blur-xl bg-black/30 border-b border-white/5">
        <div className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8 flex items-center justify-between h-16">
          <div className="flex items-center gap-3">
            <button
              onClick={() => setCollapsed((v) => !v)}
              className="p-2 rounded-xl hover:bg-white/5 transition-colors"
              aria-label="Toggle sidebar"
            >
              {collapsed ? <ChevronRight size={18} /> : <ChevronLeft size={18} />}
            </button>
            <div className="leading-tight">
              <div className="text-sm text-gray-300">WebSpeak Admin</div>
              <div className="text-base font-semibold text-white">{title}</div>
            </div>
          </div>

          <div className="flex items-center gap-3">
            <div className="hidden md:flex text-xs text-gray-400 items-center gap-2">
              <span className="inline-flex w-2 h-2 rounded-full bg-green-400" />
              Admin session active
            </div>
            <button
              onClick={() => {
                logoutAdmin()
                navigate('/admin/login', { replace: true })
              }}
              className="inline-flex items-center gap-2 amazon-btn-secondary px-3 py-2 rounded-xl border border-white/10 hover:bg-white/5"
            >
              <LogOut size={16} />
              <span className="hidden sm:inline">Logout</span>
            </button>
          </div>
        </div>
      </div>

      <div className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8">
        <div className="flex gap-4 pt-6">
          <AnimatePresence initial={false}>
            <motion.aside
              initial={{ width: collapsed ? 72 : 264 }}
              animate={{ width: collapsed ? 72 : 264 }}
              transition={{ duration: 0.2 }}
              className="hidden sm:block"
            >
              <div className="h-[calc(100vh-7rem)] sticky top-[6.5rem] overflow-y-auto pr-2">
                <div className="rounded-2xl border border-white/5 bg-white/5 backdrop-blur-xl p-2">
                  <div className="px-2 pb-2">
                    <div className="text-xs text-gray-400">Navigation</div>
                  </div>

                  <nav className="space-y-1">
                    {sidebarItems.map((item) => {
                      const Icon = item.icon
                      return (
                        <NavLink
                          key={item.to}
                          to={item.to}
                          className={({ isActive }) =>
                            [
                              'group flex items-center gap-3 px-3 py-3 rounded-xl transition-all',
                              isActive ? 'bg-white/10 border border-white/10' : 'hover:bg-white/5',
                            ].join(' ')
                          }
                        >
                          <Icon size={18} className="text-gray-200" />
                          <span className={collapsed ? 'hidden' : 'font-medium'}>{item.label}</span>
                        </NavLink>
                      )
                    })}
                  </nav>

                  <div className="mt-4 px-3 py-3 rounded-xl bg-gradient-to-br from-brand-500/10 to-purple-500/10 border border-white/5">
                    <div className={collapsed ? 'hidden' : 'text-xs text-gray-300'}>
                      Role-based admin panel
                      <div className="text-[11px] text-gray-400 mt-1">Protected under /admin/* routes</div>
                    </div>
                  </div>
                </div>
              </div>
            </motion.aside>
          </AnimatePresence>

          <main className="flex-1">
            <Outlet />
          </main>
        </div>
      </div>
    </div>
  )
}

