import { useEffect, useMemo, useState } from 'react'
import { motion } from 'framer-motion'
import { Plus, Trash2, Pencil, Upload } from 'lucide-react'

import toast from 'react-hot-toast'
import productService from '../../services/productService'

const money = (n) => Number(n || 0).toLocaleString('en-IN')

const makePayload = (draft) => {
  return {
    name: draft.name.trim(),
    category: draft.category.trim() || 'General',
    price: Number(draft.price || 0),
    discountPct: Number(draft.discountPct || 0),
    stock: Number(draft.stock || 0),
    imageUrl: draft.imageUrl || '',
    enabled: draft.enabled ?? true,
    bannerType: draft.bannerType || 'mid',
  }
}


export default function AdminProducts() {
  const [query, setQuery] = useState('')
  const [draft, setDraft] = useState({
    name: '',
    category: 'General',
    price: '0',
    discountPct: '0',
    stock: '0',
    imageUrl: '',
    enabled: true,
    bannerType: 'mid',
  })

  const [editingId, setEditingId] = useState(null)
  const [busy, setBusy] = useState(false)
  const [products, setProducts] = useState([])

  const refresh = async () => {
    const res = await productService.getProducts()
    setProducts(Array.isArray(res) ? res : [])
  }


  useEffect(() => {
    // initial load
    refresh().catch(() => {})
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  const filtered = useMemo(() => {
    const q = query.trim().toLowerCase()
    if (!q) return products
    return products.filter((p) => String(p.name || '').toLowerCase().includes(q) || String(p.category || '').toLowerCase().includes(q))
  }, [products, query])

  const saveChanges = async () => {
    const name = draft.name.trim()
    if (!name) return

    setBusy(true)
    try {
      if (editingId) {
        await productService.updateProduct(editingId, makePayload(draft))
      } else {
        await productService.createProduct(makePayload(draft))
      }

      toast.success(editingId ? 'Product updated' : 'Product added')
      setEditingId(null)
      setDraft({ name: '', category: 'General', price: '0', discountPct: '0', stock: '0', imageUrl: '', enabled: true, bannerType: 'mid' })
      await refresh()
    } catch {
      toast.error('Failed to save product')
    } finally {
      setBusy(false)
    }
  }




const [imgBusy, setImgBusy] = useState(false)

const onImageFile = async (file) => {
  // Demo-only preview removed; backend accepts imageUrl string.
  // Keep ability to set imageUrl via FileReader preview if user wants to paste/use it.
  setImgBusy(true)
  try {
    const reader = new FileReader()
    const dataUrl = await new Promise((resolve, reject) => {
      reader.onload = () => resolve(reader.result)
      reader.onerror = reject
      reader.readAsDataURL(file)
    })
    setDraft((d) => ({ ...d, imageUrl: String(dataUrl || '') }))
  } finally {
    setImgBusy(false)
  }
}

const edit = (p) => {

    setEditingId(p.id)
    setDraft({
      name: p.name || '',
      category: p.category || 'General',
      price: String(p.price ?? 0),
      discountPct: String(p.discountPct ?? 0),
      stock: String(p.stock ?? 0),
      imageUrl: p.imageUrl || '',
    })
  }

  const del = async (id) => {
    setBusy(true)
    try {
      await productService.deleteProduct(id)
      toast.success('Product deleted')
      if (editingId === id) {
        setEditingId(null)
        setDraft({ name: '', category: 'General', price: '0', discountPct: '0', stock: '0', imageUrl: '', enabled: true, bannerType: 'mid' })
      }
      await refresh()
    } catch {
      toast.error('Failed to delete product')
    } finally {
      setBusy(false)
    }
  }


  return (
    <div className="px-0 sm:px-0">
      <div className="flex items-center justify-between mb-4 flex-col sm:flex-row gap-3">
        <div>
          <h1 className="text-2xl font-bold text-white">Products Management</h1>
          <p className="text-gray-400 text-sm">Add/edit products, manage stock, categories, and discounts.</p>
        </div>

        <div className="w-full sm:w-auto">
          <input
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            placeholder="Search products..."
            className="w-full sm:w-80 bg-white/5 border border-white/10 rounded-xl px-3 py-2 text-sm outline-none focus:border-brand-400/50"
          />
        </div>
      </div>

      <div className="glass-dark rounded-2xl p-5 mb-4">
        <div className="flex items-start justify-between gap-4 flex-col md:flex-row">
          <div className="">
            <h2 className="text-lg font-bold text-white">{editingId ? 'Edit Product' : 'Add New Product'}</h2>
            <p className="text-gray-400 text-sm mt-1">Image is stored as a URL. Paste an image URL.</p>

          </div>

          <div className="flex items-center gap-2">
            <button
              onClick={() => {
                setEditingId(null)
                setDraft({ name: '', category: 'General', price: '0', discountPct: '0', stock: '0', imageUrl: '' })
              }}
              className="amazon-btn-secondary amazon-btn"
              type="button"
            >
              Reset
            </button>

            <button onClick={saveChanges} disabled={busy} className="amazon-btn-primary amazon-btn" type="button">
              <Plus size={16} className="inline mr-2" />
              {busy ? 'Saving...' : 'Save Changes'}
            </button>

          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mt-4">
          <div>
            <label className="text-xs text-gray-400">Name</label>
            <input value={draft.name} onChange={(e) => setDraft((d) => ({ ...d, name: e.target.value }))} className="w-full mt-2 bg-white/5 border border-white/10 rounded-xl px-3 py-2 text-sm outline-none" />
          </div>
          <div>
            <label className="text-xs text-gray-400">Category</label>
            <input value={draft.category} onChange={(e) => setDraft((d) => ({ ...d, category: e.target.value }))} className="w-full mt-2 bg-white/5 border border-white/10 rounded-xl px-3 py-2 text-sm outline-none" />
          </div>
          <div>
            <label className="text-xs text-gray-400">Stock</label>
            <input value={draft.stock} onChange={(e) => setDraft((d) => ({ ...d, stock: e.target.value }))} className="w-full mt-2 bg-white/5 border border-white/10 rounded-xl px-3 py-2 text-sm outline-none" />
          </div>

          <div>
            <label className="text-xs text-gray-400">Price</label>
            <input value={draft.price} onChange={(e) => setDraft((d) => ({ ...d, price: e.target.value }))} className="w-full mt-2 bg-white/5 border border-white/10 rounded-xl px-3 py-2 text-sm outline-none" />
          </div>
          <div>
            <label className="text-xs text-gray-400">Discount %</label>
            <input
              value={draft.discountPct}
              onChange={(e) => setDraft((d) => ({ ...d, discountPct: e.target.value }))}
              className="w-full mt-2 bg-white/5 border border-white/10 rounded-xl px-3 py-2 text-sm outline-none"
            />
          </div>

          <div className="md:col-span-1">
            <label className="text-xs text-gray-400">Upload Image</label>
            <div className="mt-2">
              <div className="flex items-center gap-3">
                <label className="amazon-btn-secondary amazon-btn cursor-pointer inline-flex items-center justify-center gap-2">
                  <Upload size={16} />
                  {imgBusy ? 'Uploading...' : 'Choose file'}
                  <input type="file" accept="image/*" className="hidden" onChange={(e) => e.target.files?.[0] && onImageFile(e.target.files[0])} />
                </label>
              </div>
              <div className="mt-3">
                {draft.imageUrl ? (
                  <img src={draft.imageUrl} alt="preview" className="w-24 h-24 rounded-xl object-cover border border-white/10" />
                ) : (
                  <div className="text-xs text-gray-500">No image selected.</div>
                )}
              </div>
            </div>
          </div>
        </div>
      </div>

      <motion.div className="glass-dark rounded-2xl p-5" initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
        <h2 className="text-lg font-bold text-white mb-3">Product List</h2>

        <div className="overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr className="text-gray-400 text-xs border-b border-white/10">
                <th className="text-left py-3">Product</th>
                <th className="text-left py-3">Category</th>
                <th className="text-left py-3">Price</th>
                <th className="text-left py-3">Discount</th>
                <th className="text-left py-3">Stock</th>
                <th className="text-left py-3">Actions</th>
              </tr>
            </thead>
            <tbody>
              {filtered.map((p) => {
                const finalPrice = Number(p.price || 0) * (1 - Number(p.discountPct || 0) / 100)
                return (
                  <tr key={p.id} className="border-b border-white/5">
                    <td className="py-3">
                      <div className="flex items-center gap-3">
                        <img
                          src={p.imageUrl || 'https://via.placeholder.com/64?text=No+Image'}
                          alt={p.name}
                          className="w-10 h-10 rounded-xl object-cover border border-white/10"
                        />
                        <div>
                          <div className="text-white font-semibold">{p.name}</div>
                          <div className="text-gray-400 text-xs font-mono">{p.id}</div>
                        </div>
                      </div>
                    </td>
                    <td className="py-3 text-gray-200">{p.category}</td>
                    <td className="py-3 text-white font-semibold">₹{money(p.price)}</td>
                    <td className="py-3 text-gray-200">{p.discountPct || 0}%</td>
                    <td className="py-3 text-gray-200">{p.stock ?? 0}</td>
                    <td className="py-3">
                      <div className="flex items-center gap-2">
                        <button onClick={() => edit(p)} className="amazon-btn-secondary amazon-btn inline-flex items-center gap-2" type="button">
                          <Pencil size={16} /> Edit
                        </button>
                        <button onClick={() => del(p.id)} className="amazon-btn-danger amazon-btn inline-flex items-center gap-2" type="button">
                          <Trash2 size={16} /> Delete
                        </button>
                      </div>
                      <div className="text-xs text-gray-500 mt-1">Final: ₹{money(finalPrice)}</div>
                    </td>
                  </tr>
                )
              })}

              {filtered.length === 0 && (
                <tr>
                  <td colSpan={6} className="py-12 text-center text-gray-400">No products found.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </motion.div>
    </div>
  )
}

