import { Navigate, Outlet } from 'react-router-dom'
import { useSelector } from 'react-redux'

export default function RequireAuth({ redirectTo = '/login' }) {
  // Token is the source of truth for demo frontend-only auth
  const token = localStorage.getItem('token')
  const { isAuthenticated } = useSelector((state) => state.auth)
  const role = localStorage.getItem('role')

  // Demo: user auth is only for normal users. Admin routes are protected separately.
  const authed = (!!token || !!isAuthenticated) && role !== 'admin'


  if (!authed) {
    return <Navigate to={redirectTo} replace />
  }

  return <Outlet />
}



