import React from 'react'
import ReactDOM from 'react-dom/client'
import { Provider } from 'react-redux'
import { BrowserRouter, useNavigate } from 'react-router-dom'
import App from './App'

import { store } from './redux/store'
import './index.css'
import { hydrateAuth } from './redux/slices/authHydration'

function ForceLoginRouteListener() {
  const navigate = useNavigate()

  React.useEffect(() => {
    const handler = () => navigate('/login', { replace: true })
    window.addEventListener('auth:force-login', handler)
    return () => window.removeEventListener('auth:force-login', handler)
  }, [navigate])

  return null
}


// Hydrate auth state once on app start so Header/RequireAuth don't bounce
store.dispatch(hydrateAuth())

ReactDOM.createRoot(document.getElementById('root')).render(
  <React.StrictMode>
    <Provider store={store}>
      <BrowserRouter>
        <ForceLoginRouteListener />
        <App />
      </BrowserRouter>
    </Provider>
  </React.StrictMode>,
)





