import { useEffect, useMemo, useState } from 'react'
import { motion } from 'framer-motion'
import { ensureAdminSession, getAdminState, commitAdminState } from '../adminStore'
import { Search, Ban, Trash2 } from 'lucide-react'

export default function AdminUsers() {
  const [query, setQuery] = useState('')
  const [busy, setBusy] = useState(null)

  useEffect(() => {
    ensureAdminSession()
  }, [])

  const { data } = useMemo(() => getAdminState(), [busy])
  const users = data?.users || []

  const filtered = useMemo(() => {
    const q = query.trim().toLowerCase()
    if (!q) return users
    return users.filter((u) => String(u.email || '').toLowerCase().includes(q) || String(u.id || '').toLowerCase().includes(q))
  }, [users, query])

  const blockToggle = (userId) => {
    setBusy(userId)
    const next = structuredClone(data)
    next.users = next.users.map((u) => (u.id === userId ? { ...u, blocked: !u.blocked } : u))
    commitAdminState(next)
    setBusy(null)
  }

  const del = (userId) => {
    setBusy(userId)
    const next = structuredClone(data)
    next.users = next.users.filter((u) => u.id !== userId)
    // optional: also remove their orders in demo
    next.orders = (next.orders || []).filter((o) => o.userId !== userId)
    commitAdminState(next)
    setBusy(null)
  }

  const orders = data?.orders || []

  return (
    <div className="px-0 sm:px-0">
      <div className="flex items-center justify-between mb-4 flex-col sm:flex-row gap-3">
        <div>
          <h1 className="text-2xl font-bold text-white">Users Management</h1>
          <p className="text-gray-400 text-sm">List users, show orders count, block/unblock and delete.</p>
        </div>

        <div className="w-full sm:w-auto">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
            <input
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              placeholder="Search by email..."
              className="w-full sm:w-80 bg-white/5 border border-white/10 rounded-xl pl-10 pr-3 py-2 text-sm outline-none focus:border-brand-400/50"
            />
          </div>
        </div>
      </div>

      <motion.div className="glass-dark rounded-2xl p-5" initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
        <h2 className="text-lg font-bold text-white mb-3">User List</h2>

        <div className="overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr className="text-gray-400 text-xs border-b border-white/10">
                <th className="text-left py-3">User</th>
                <th className="text-left py-3">Email</th>
                <th className="text-left py-3">Orders</th>
                <th className="text-left py-3">Status</th>
                <th className="text-left py-3">Actions</th>
              </tr>
            </thead>
            <tbody className="text-sm">
              {filtered.map((u) => {
                const userOrdersCount = (orders || []).filter((o) => o.userId === u.id).length
                const blocked = !!u.blocked
                return (
                  <tr key={u.id} className="border-b border-white/5">
                    <td className="py-3 text-white font-semibold">{u.name || u.id}</td>
                    <td className="py-3 text-gray-200">{u.email}</td>
                    <td className="py-3 text-gray-200">{userOrdersCount}</td>
                    <td className="py-3">
                      <span className={blocked ? 'px-2 py-1 rounded-lg text-xs bg-red-500/10 text-red-300 border border-red-500/20' : 'px-2 py-1 rounded-lg text-xs bg-green-500/10 text-green-300 border border-green-500/20'}>
                        {blocked ? 'Blocked' : 'Active'}
                      </span>
                    </td>
                    <td className="py-3">
                      <div className="flex items-center gap-2 flex-wrap">
                        <button
                          onClick={() => blockToggle(u.id)}
                          disabled={busy === u.id}
                          className="amazon-btn-secondary amazon-btn inline-flex items-center gap-2"
                          type="button"
                        >
                          <Ban size={16} /> {blocked ? 'Unblock' : 'Block'}
                        </button>
                        <button
                          onClick={() => del(u.id)}
                          disabled={busy === u.id}
                          className="amazon-btn-danger amazon-btn inline-flex items-center gap-2"
                          type="button"
                        >
                          <Trash2 size={16} /> Delete
                        </button>
                      </div>
                    </td>
                  </tr>
                )
              })}
              {filtered.length === 0 && (
                <tr>
                  <td colSpan={5} className="py-12 text-center text-gray-400">No users found.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </motion.div>
    </div>
  )
}

