import { createSlice, createAsyncThunk } from '@reduxjs/toolkit'
import productService from '../../services/productService'

export const fetchProducts = createAsyncThunk('product/fetchProducts', async (params, { rejectWithValue }) => {
  try {
    return await productService.getProducts(params)
  } catch (error) {
    return rejectWithValue(error.response?.data?.message || 'Failed to fetch products')
  }
})

export const fetchProductById = createAsyncThunk('product/fetchProductById', async (id, { rejectWithValue }) => {
  try {
    return await productService.getProductById(id)
  } catch (error) {
    return rejectWithValue(error.response?.data?.message || 'Failed to fetch product')
  }
})

export const searchProducts = createAsyncThunk('product/search', async (query, { rejectWithValue }) => {
  try {
    return await productService.searchProducts(query)
  } catch (error) {
    return rejectWithValue(error.response?.data?.message || 'Search failed')
  }
})

const initialState = {
  products: [],
  product: null,
  searchResults: [],
  loading: false,
  error: null,
}

const productSlice = createSlice({
  name: 'product',
  initialState,
  reducers: {
    clearSearch: (state) => {
      state.searchResults = []
    },
  },
  extraReducers: (builder) => {
    builder
      .addCase(fetchProducts.pending, (state) => { state.loading = true })
      .addCase(fetchProducts.fulfilled, (state, action) => {
        state.loading = false
        state.products = action.payload
      })
      .addCase(fetchProducts.rejected, (state, action) => {
        state.loading = false
        state.error = action.payload
      })
      .addCase(fetchProductById.pending, (state) => { state.loading = true })
      .addCase(fetchProductById.fulfilled, (state, action) => {
        state.loading = false
        state.product = action.payload
      })
      .addCase(searchProducts.pending, (state) => { state.loading = true })
      .addCase(searchProducts.fulfilled, (state, action) => {
        state.loading = false
        state.searchResults = action.payload
      })
  },
})

export const { clearSearch } = productSlice.actions
export default productSlice.reducer

