import { useState } from 'react'
import { Link } from 'react-router-dom'
import { motion } from 'framer-motion'
import { User, Package, MapPin, CreditCard, Bell, Heart, LogOut } from 'lucide-react'
import { useSelector, useDispatch } from 'react-redux'
import { logout } from '../redux/slices/authSlice'

const tabs = [
  { id: 'profile', label: 'Profile', icon: User },
  { id: 'orders', label: 'My Orders', icon: Package },
  { id: 'addresses', label: 'Addresses', icon: MapPin },
  { id: 'payments', label: 'Payments', icon: CreditCard },
  { id: 'notifications', label: 'Notifications', icon: Bell },
]

export default function UserDashboardPage() {
  const [activeTab, setActiveTab] = useState('orders')
  const { user } = useSelector(state => state.auth)
  const dispatch = useDispatch()

  return (
    <div className="min-h-screen section-padding py-8">
      <div className="max-w-6xl mx-auto">
        <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
          {/* Sidebar */}
          <div className="lg:col-span-1">
            <div className="glass-dark rounded-2xl p-6 space-y-6 sticky top-24">
              <div className="text-center">
                <div className="w-20 h-20 mx-auto bg-gradient-to-br from-brand-500 to-neon-blue rounded-full flex items-center justify-center text-2xl font-bold text-white">
                  {user?.firstName?.[0] || 'U'}
                </div>
                <h3 className="text-white font-semibold mt-3">{user?.firstName} {user?.lastName}</h3>
                <p className="text-gray-400 text-sm">{user?.email}</p>
              </div>
              <nav className="space-y-1">
                {tabs.map(tab => (
                  <button
                    key={tab.id}
                    onClick={() => setActiveTab(tab.id)}
                    className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl text-sm transition-colors
                      ${activeTab === tab.id ? 'bg-brand-600 text-white' : 'text-gray-400 hover:bg-white/5'}`}
                  >
                    <tab.icon size={18} />
                    {tab.label}
                  </button>
                ))}
                <button
                  onClick={() => dispatch(logout())}
                  className="w-full flex items-center gap-3 px-4 py-3 rounded-xl text-sm text-red-400 hover:bg-red-500/10 transition-colors"
                >
                  <LogOut size={18} />
                  Logout
                </button>
              </nav>
            </div>
          </div>

          {/* Content */}
          <div className="lg:col-span-3">
            <motion.div
              key={activeTab}
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              className="glass-dark rounded-2xl p-6 md:p-8"
            >
              {activeTab === 'orders' && (
                <div className="space-y-4">
                  <h2 className="text-xl font-bold text-white mb-4">My Orders</h2>
                  {['WSP-2024-000001', 'WSP-2024-000002'].map((order, i) => (
                    <div key={order} className="p-4 border border-dark-border rounded-xl hover:border-brand-500/30 transition-colors">
                      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                        <div>
                          <p className="text-white font-medium">Order #{order}</p>
                          <p className="text-gray-400 text-sm">Dec {24 - i}, 2024 • 1 item</p>
                        </div>
                        <div className="flex items-center gap-4">
                          <span className={`px-3 py-1 rounded-lg text-sm font-medium
                            ${i === 0 ? 'bg-green-500/10 text-green-400' : 'bg-brand-500/10 text-brand-400'}`}>
                            {i === 0 ? 'Delivered' : 'Shipped'}
                          </span>
                          <Link to={`/track/${order}`} className="text-brand-400 hover:text-brand-300 text-sm">
                            Track
                          </Link>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              )}

              {activeTab === 'profile' && (
                <div className="space-y-6">
                  <h2 className="text-xl font-bold text-white">Profile Information</h2>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div>
                      <label className="text-gray-400 text-sm">First Name</label>
                      <input type="text" defaultValue={user?.firstName} className="input-field mt-1" />
                    </div>
                    <div>
                      <label className="text-gray-400 text-sm">Last Name</label>
                      <input type="text" defaultValue={user?.lastName} className="input-field mt-1" />
                    </div>
                    <div>
                      <label className="text-gray-400 text-sm">Email</label>
                      <input type="email" defaultValue={user?.email} className="input-field mt-1" readOnly />
                    </div>
                    <div>
                      <label className="text-gray-400 text-sm">Phone</label>
                      <input type="tel" defaultValue={user?.phoneNumber} className="input-field mt-1" />
                    </div>
                  </div>
                  <button className="btn-primary">Save Changes</button>
                </div>
              )}

              {activeTab === 'addresses' && (
                <div className="space-y-4">
                  <h2 className="text-xl font-bold text-white">Saved Addresses</h2>
                  <div className="p-4 border border-dark-border rounded-xl">
                    <div className="flex justify-between items-start">
                      <div>
                        <p className="text-white font-medium">Home</p>
                        <p className="text-gray-400 text-sm mt-1">123 Main Street, Bangalore, Karnataka - 560001</p>
                        <span className="text-xs bg-brand-600 text-white px-2 py-1 rounded mt-2 inline-block">Default</span>
                      </div>
                      <button className="text-gray-400 hover:text-white text-sm">Edit</button>
                    </div>
                  </div>
                  <button className="btn-secondary w-full">+ Add New Address</button>
                </div>
              )}

              {activeTab === 'payments' && (
                <div className="space-y-4">
                  <h2 className="text-xl font-bold text-white">Payment History</h2>
                  <div className="p-4 border border-dark-border rounded-xl">
                    <div className="flex justify-between items-center">
                      <div>
                        <p className="text-white font-medium">₹2,499</p>
                        <p className="text-gray-400 text-sm">UPI Payment • Dec 24, 2024</p>
                      </div>
                      <span className="text-green-400 text-sm">Success</span>
                    </div>
                  </div>
                </div>
              )}

              {activeTab === 'notifications' && (
                <div className="space-y-4">
                  <h2 className="text-xl font-bold text-white">Notifications</h2>
                  <p className="text-gray-400">No new notifications</p>
                </div>
              )}
            </motion.div>
          </div>
        </div>
      </div>
    </div>
  )
}

