import { Link } from 'react-router-dom'

export default function AdminNotFound() {
  return (
    <div className="px-0 sm:px-0">
      <div className="glass-dark rounded-2xl p-10 text-center">
        <div className="text-2xl font-bold text-white">Admin page not found</div>
        <div className="text-gray-400 text-sm mt-2">The route you opened does not exist.</div>
        <div className="mt-5">
          <Link to="/admin/dashboard" className="amazon-btn-primary amazon-btn inline-flex justify-center">
            Go to Dashboard
          </Link>
        </div>
      </div>
    </div>
  )
}

