import { useMemo, useState } from 'react'
import { Link, useNavigate } from 'react-router-dom'
import { useDispatch, useSelector } from 'react-redux'
import { motion } from 'framer-motion'
import { ArrowRight, Lock, Mail } from 'lucide-react'

import { setUser } from '../redux/slices/authSlice'



export default function LoginPage() {
  const [formData, setFormData] = useState({ email: '', password: '' })
  const dispatch = useDispatch()
  const navigate = useNavigate()




  const [loading, setLoading] = useState(false)

  const handleLogin = async (e) => {
    e.preventDefault()

    setLoading(true)
    try {
      const email = formData.email
      const password = formData.password

      if (!email || !password) {
        alert("Enter email and password")
        return
      }

      localStorage.setItem('token', 'demo-token')

      // Keep navbar state in sync immediately
      const existingUser = localStorage.getItem('user')
      const parsedUser = existingUser ? JSON.parse(existingUser) : null
      const userData = parsedUser || { firstName: 'User', email }
      localStorage.setItem('user', JSON.stringify(userData))
      dispatch(setUser(userData))

      alert('Login Successful')
      navigate('/')
    } finally {
      setLoading(false)
    }
  }


  return (
    <div className="min-h-screen flex items-center justify-center section-padding py-12">
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        className="w-full max-w-md"
      >
        <div className="glass-dark rounded-3xl p-8 space-y-6">
          <div className="text-center space-y-2">
            <h1 className="text-2xl font-bold text-white">Welcome Back</h1>
            <p className="text-gray-400">Sign in to your WebSpeak account</p>
          </div>

          <form onSubmit={handleLogin} className="space-y-4">

            <div className="relative">
              <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
              <input
                type="email"
                placeholder="Email address"
                value={formData.email}
                onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                className="input-field pl-12"
                required
              />
            </div>

            <div className="relative">
              <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
              <input
                type="password"
                placeholder="Password"
                value={formData.password}
                onChange={(e) => setFormData({ ...formData, password: e.target.value })}
                className="input-field pl-12"
                required
              />
            </div>

            <div className="flex items-center justify-between text-sm">
              <label className="flex items-center gap-2 text-gray-400 cursor-pointer">
                <input type="checkbox" className="rounded bg-dark-card border-dark-border" />
                Remember me
              </label>
              <Link to="/forgot-password" className="text-brand-400 hover:text-brand-300">
                Forgot password?
              </Link>
            </div>

            <button
              type="submit"
              disabled={loading}
              className="w-full btn-primary py-3 flex items-center justify-center gap-2 disabled:opacity-50"
            >
              {loading ? 'Signing in...' : 'Sign In'}

              {!loading && <ArrowRight size={18} />}
            </button>
          </form>

          <div className="relative">
            <div className="absolute inset-0 flex items-center">
              <div className="w-full border-t border-dark-border" />
            </div>
            <div className="relative flex justify-center text-sm">
              <span className="px-2 bg-dark-card text-gray-500">Or continue with</span>
            </div>
          </div>



          <p className="text-center text-gray-400 text-sm">
            Don't have an account?{' '}
            <button
              type="button"
              onClick={() => navigate('/register')}
              className="text-brand-400 hover:text-brand-300 font-medium cursor-pointer"
            >
              Create one
            </button>
          </p>

          {/* Login selection system */}
          <motion.div
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.35 }}
            className="pt-2"
          >
            <div className="flex items-center justify-center text-xs text-gray-400 mb-3">
              <span className="px-3 py-1 rounded-full bg-dark-card/40 border border-dark-border/60">
                Continue as
              </span>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
              {/* User Login */}
              <motion.button
                whileHover={{ y: -2, scale: 1.01 }}
                whileTap={{ scale: 0.99 }}
                type="button"
                onClick={() => {
                  // Real-world feel: focus/scroll to the existing user login form.
                  const el = document.querySelector('input[type="email"]')
                  if (el) el.focus()
                }}
                className="relative overflow-hidden rounded-2xl p-4 text-left border border-cyan-400/25 bg-gradient-to-br from-cyan-500/15 to-blue-500/10 backdrop-blur-md hover:border-cyan-400/50 transition-all"
              >
                <div className="absolute inset-0 bg-gradient-to-r from-cyan-500/20 to-transparent opacity-0 hover:opacity-100 transition-opacity" />
                <div className="relative flex items-start gap-3">
                  <div className="w-10 h-10 rounded-xl bg-cyan-500/10 border border-cyan-500/25 flex items-center justify-center">
                    <Mail size={18} className="text-cyan-200" />
                  </div>
                  <div>
                    <div className="font-semibold text-white">User Login</div>
                    <div className="text-xs text-gray-300 mt-1">Sign in as customer</div>
                  </div>
                </div>
                <div className="relative mt-3 flex items-center justify-between text-xs text-gray-300">
                  <span>Go to user form</span>
                  <ArrowRight size={16} className="text-cyan-200" />
                </div>
              </motion.button>

              {/* Admin Login */}
              <motion.button
                whileHover={{ y: -2, scale: 1.01 }}
                whileTap={{ scale: 0.99 }}
                type="button"
                onClick={() => navigate('/admin/login')}
                className="relative overflow-hidden rounded-2xl p-4 text-left border border-orange-400/25 bg-gradient-to-br from-orange-500/15 to-red-500/10 backdrop-blur-md hover:border-orange-400/50 transition-all"
              >
                <div className="absolute inset-0 bg-gradient-to-r from-orange-500/20 to-transparent opacity-0 hover:opacity-100 transition-opacity" />
                <div className="relative flex items-start gap-3">
                  <div className="w-10 h-10 rounded-xl bg-orange-500/10 border border-orange-500/25 flex items-center justify-center">
                    {/* Simple shield look */}
                    <span className="text-orange-200 font-bold">🛡️</span>
                  </div>
                  <div>
                    <div className="font-semibold text-white">Admin Login</div>
                    <div className="text-xs text-gray-300 mt-1">Restricted dashboard access</div>
                  </div>
                </div>
                <div className="relative mt-3 flex items-center justify-between text-xs text-gray-300">
                  <span>Open admin auth</span>
                  <ArrowRight size={16} className="text-orange-200" />
                </div>
              </motion.button>
            </div>
          </motion.div>

        </div>
      </motion.div>
    </div>
  )
}

