import React, { useEffect, useState } from 'react'
import { Link, useParams } from 'react-router-dom'

import { Package, Truck, CheckCircle, MapPin, Clock } from 'lucide-react'

export default function OrderTrackingPage() {

  const { orderId } = useParams()

  const [order, setOrder] = useState(null)

  useEffect(() => {
    let mounted = true

    ;(async () => {
      try {
        const res = await fetch(`http://localhost:8081/api/orders/${orderId}`, {
          headers: {
            'Content-Type': 'application/json',
            Authorization: localStorage.getItem('token') ? `Bearer ${localStorage.getItem('token')}` : '',
          },
        })

        if (!res.ok) throw new Error('Failed to fetch order')
        const data = await res.json()
        if (mounted) setOrder(data)
      } catch {
        if (mounted) setOrder(null)
      }
    })()

    return () => {
      mounted = false
    }
  }, [orderId])

  const steps = [
    { key: 'ORDERED', label: 'Ordered', icon: <Package size={18} /> },
    { key: 'CONFIRMED', label: 'Packed', icon: <CheckCircle size={18} /> },
    { key: 'SHIPPED', label: 'Shipped', icon: <Truck size={18} /> },
    { key: 'OUT_FOR_DELIVERY', label: 'Out for Delivery', icon: <MapPin size={18} /> },
    { key: 'DELIVERED', label: 'Delivered', icon: <CheckCircle size={18} /> },
  ]


  const status = order?.status || 'ORDERED'



  const orderStepIndex = steps.findIndex((s) => s.key === status)
  const activeIndex = orderStepIndex === -1 ? 0 : orderStepIndex

  return (
    <div className="min-h-screen section-padding py-8">
      <div className="max-w-3xl mx-auto space-y-8">
        <div className="flex items-center justify-between">
          <h1 className="text-2xl font-bold text-white">Track Order</h1>
          <span className="px-4 py-2 bg-dark-card rounded-xl text-gray-300 text-sm font-mono">{orderId}</span>
        </div>

        <div className="glass-dark rounded-2xl p-6 md:p-8">
          <div className="flex items-center gap-4 mb-8">
            <img
              src={order?.imageUrl || 'https://images.unsplash.com/photo-1608043152269-423dbba4e7e1?w=100'}
              alt="Product"
              className="w-16 h-16 object-cover rounded-xl"
              onError={(e) => {
                e.currentTarget.src = 'https://images.unsplash.com/photo-1608043152269-423dbba4e7e1?w=100'
              }}
            />
            <div>
              <p className="text-white font-medium">{order?.productName || 'WebSpeak BassX Pro 40W'}</p>
              <p className="text-gray-400 text-sm">Black | Qty: {order?.quantity || 1}</p>
            </div>
          </div>

          <div className="space-y-0">
            {steps.map((step, i) => {
              const completed = i <= activeIndex
              return (
                <div key={step.key} className="flex gap-4">
                  <div className="flex flex-col items-center">
                    <div
                      className={`w-10 h-10 rounded-full flex items-center justify-center transition-colors ${
                        completed ? 'bg-brand-500 text-white' : 'bg-dark-border text-gray-500'
                      }`}
                    >
                      {step.icon}
                    </div>
                    {i < steps.length - 1 && (
                      <div
                        className={`w-0.5 h-16 transition-colors ${completed ? 'bg-brand-500' : 'bg-dark-border'}`}
                      />
                    )}
                  </div>
                  <div className="pb-8">
                    <p className="text-white font-medium">{step.label}</p>
                    <p className="text-gray-400 text-sm flex items-center gap-1 mt-1">
                      <Clock size={12} />
                      {completed ? 'Completed' : 'Pending'}
                    </p>
                  </div>
                </div>
              )
            })}
          </div>
        </div>

        <div className="glass-dark rounded-2xl p-6">
          <h3 className="font-semibold text-white mb-4">Delivery Address</h3>
          <div className="flex items-start gap-3">
            <MapPin className="text-brand-400 mt-1" size={18} />
            <div>
              <p className="text-white">{order?.address?.fullName || 'John Doe'}</p>
              <p className="text-gray-400 text-sm">
                {(order?.address?.doorNumber || '123 Main Street') + ', ' + (order?.address?.city || 'Bangalore') + ', ' + (order?.address?.state || 'Karnataka') + ' - ' + (order?.address?.pincode || '560001')}
              </p>
              <p className="text-gray-400 text-sm">Phone: +91 {order?.address?.mobileNumber || '99999 99999'}</p>
            </div>
          </div>
        </div>

        <Link
          to="/dashboard/orders"
          className="btn-secondary w-full inline-flex items-center justify-center"
        >
          View All Orders
        </Link>
      </div>
    </div>
  )
}


