import { useEffect, useMemo, useState } from 'react'
import { motion } from 'framer-motion'
import { ensureAdminSession } from '../adminStore'
import api from '../../services/api'
import orderService from '../../services/orderService'
import { Search, Truck, Package2, MapPin, CreditCard } from 'lucide-react'


const statusOptions = ['Pending', 'Confirmed', 'Shipped', 'Delivered', 'Cancelled']

function formatMoney(v) {
  const n = Number(v || 0)
  return n.toLocaleString('en-IN', { style: 'currency', currency: 'INR', maximumFractionDigits: 0 })
}

function StatusPill({ status }) {
  const color =
    status === 'Delivered'
      ? 'bg-green-500/10 text-green-300 border border-green-500/20'
      : status === 'Shipped'
        ? 'bg-blue-500/10 text-blue-300 border border-blue-500/20'
        : status === 'Cancelled'
          ? 'bg-red-500/10 text-red-300 border border-red-500/20'
          : 'bg-yellow-500/10 text-yellow-200 border border-yellow-500/20'

  return <span className={`px-2 py-1 rounded-lg text-xs font-medium ${color}`}>{status}</span>
}

export default function AdminOrders() {
  const [query, setQuery] = useState('')
  const [updatingId, setUpdatingId] = useState(null)

  const [orders, setOrders] = useState([])

  useEffect(() => {
    ensureAdminSession()

    let mounted = true
    ;(async () => {
      try {
        const list = await orderService.getOrders()
        if (!mounted) return
        setOrders(Array.isArray(list) ? list : [])
      } catch {
        if (!mounted) return
        setOrders([])
      }
    })()

    return () => {
      mounted = false
    }
  }, [updatingId])


  const filtered = useMemo(() => {
    const q = query.trim().toLowerCase()
    if (!q) return orders
    return orders.filter((o) => {
      return (
        String(o.id || '').toLowerCase().includes(q) ||
        String(o.userEmail || '').toLowerCase().includes(q) ||
        (o.items || []).some((it) => String(it?.name || '').toLowerCase().includes(q))
      )
    })
  }, [orders, query])

  const updateStatus = async (orderId, nextStatus) => {
    setUpdatingId(orderId)
    await api.put(`/orders/${orderId}/status`, { status: nextStatus })

    // Ensure immediate appearance: re-fetch from Mongo after update.
    const list = await orderService.getOrders()
    setOrders(Array.isArray(list) ? list : [])
    setUpdatingId(null)
  }


  return (
    <div className="px-0 sm:px-0">
      <div className="flex items-center justify-between mb-4">
        <div>
          <h1 className="text-2xl font-bold text-white">Orders Management</h1>
          <p className="text-gray-400 text-sm">View customer orders and update status.</p>
        </div>

        <div className="w-full sm:w-auto">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
            <input
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              placeholder="Search by order ID, email, product"
              className="w-80 max-w-[90vw] bg-white/5 border border-white/10 rounded-xl pl-10 pr-3 py-2 text-sm outline-none focus:border-brand-400/50"
            />
          </div>
        </div>
      </div>

      <div className="glass-dark rounded-2xl p-5">
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr className="text-gray-400 text-xs border-b border-white/10">
                <th className="text-left py-3">Order</th>
                <th className="text-left py-3">Customer</th>
                <th className="text-left py-3">Address</th>
                <th className="text-left py-3">Payment</th>
                <th className="text-left py-3">Items</th>
                <th className="text-left py-3">Amount</th>
                <th className="text-left py-3">Status</th>
              </tr>
            </thead>
            <tbody className="text-sm">
              {filtered.map((o) => (
                <tr key={o.id} className="border-b border-white/5">
                  <td className="py-3">
                    <div className="text-white font-mono font-semibold">{o.id}</div>
                    <div className="text-gray-400 text-xs">{o.createdAt ? new Date(o.createdAt).toLocaleDateString() : '—'}</div>
                  </td>

                  <td className="py-3">
                    <div className="text-white">{o.userEmail}</div>
                    <div className="text-gray-400 text-xs">User ID: {o.userId}</div>
                  </td>

                  <td className="py-3">
                    <div className="flex items-start gap-2 text-gray-200">
                      <MapPin size={16} className="text-gray-400 mt-0.5" />
                      <div>
                        <div className="font-medium">{o.shippingAddress?.line1}</div>
                        <div className="text-xs text-gray-400">
                          {o.shippingAddress?.city}, {o.shippingAddress?.state} {o.shippingAddress?.zip}
                        </div>
                      </div>
                    </div>
                  </td>

                  <td className="py-3">
                    <div className="flex items-start gap-2">
                      <CreditCard size={16} className="text-gray-400 mt-0.5" />
                      <div className="text-gray-200">{o.paymentMethod}</div>
                    </div>
                  </td>

                  <td className="py-3">
                    <div className="space-y-1">
                      {(o.items || []).map((it, idx) => (
                        <div key={`${o.id}-${idx}`} className="flex items-center gap-2">
                          <Package2 size={16} className="text-gray-400" />
                          <div className="text-gray-200">
                            {it.name} <span className="text-gray-400">×{it.qty}</span>
                          </div>
                        </div>
                      ))}
                    </div>
                  </td>

                  <td className="py-3 text-white font-semibold">{formatMoney(o?.totals?.grandTotal)}</td>

                  <td className="py-3">
                    <div className="flex items-center gap-2">
                      <StatusPill status={o.status} />
                      <select
                        value={o.status}
                        onChange={(e) => updateStatus(o.id, e.target.value)}
                        disabled={updatingId === o.id}
                        className="bg-white/5 border border-white/10 rounded-xl px-2 py-2 text-xs outline-none disabled:opacity-60"
                      >
                        {statusOptions.map((s) => (
                          <option key={s} value={s} className="bg-[#070A12]">
                            {s}
                          </option>
                        ))}
                      </select>
                    </div>
                    <div className="text-gray-400 text-xs mt-1">
                      <Truck size={14} className="inline mr-1 -mt-0.5 text-gray-500" />
                      {o.status === 'Delivered' ? 'Completed' : 'In progress'}
                    </div>
                  </td>
                </tr>
              ))}

              {filtered.length === 0 && (
                <tr>
                  <td colSpan={7} className="py-12 text-center text-gray-400">
                    No orders found.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }} className="mt-4 text-xs text-gray-500">
        Orders are synced from MongoDB.
      </motion.div>

    </div>
  )
}

