import { useEffect, useMemo, useState } from 'react'
import { motion } from 'framer-motion'
import toast from 'react-hot-toast'

import adminService from '../../services/adminService'
import { ensureAdminSession } from '../adminStore'

export default function AdminAnalytics() {
  const [analytics, setAnalytics] = useState(null)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    ensureAdminSession()

    let cancelled = false
    ;(async () => {
      try {
        setLoading(true)
        const data = await adminService.getAnalytics()
        if (!cancelled) setAnalytics(data)
      } catch (e) {
        if (!cancelled) {
          toast.error('Failed to load analytics')
          setAnalytics(null)
        }
      } finally {
        if (!cancelled) setLoading(false)
      }
    })()

    return () => {
      cancelled = true
    }
  }, [])

  const money = (n) => Number(n || 0).toLocaleString('en-IN', { maximumFractionDigits: 0 })

  const cards = useMemo(() => {
    const a = analytics || {}
    return [
      { label: 'Total Users', value: a.totalUsers ?? 0 },
      { label: 'Total Products', value: a.totalProducts ?? 0 },
      { label: 'Total Orders', value: a.totalOrders ?? 0 },
      { label: 'Revenue', value: `₹${money(a.revenue)}` },
      { label: 'Pending Orders', value: a.pendingOrders ?? 0 },
      { label: 'Delivered Orders', value: a.deliveredOrders ?? 0 },
    ]
  }, [analytics])

  return (
    <div className="px-0 sm:px-0">
      <div className="flex items-center justify-between mb-4 flex-col sm:flex-row gap-3">
        <div>
          <h1 className="text-2xl font-bold text-white">Analytics</h1>
          <p className="text-gray-400 text-sm">MongoDB-backed dashboard cards.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 mb-4">
        {cards.map((s) => (
          <motion.div
            key={s.label}
            className="glass-dark rounded-2xl p-6"
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.25 }}
          >
            <div className="text-gray-400 text-sm">{s.label}</div>
            <div className="text-2xl font-bold text-white mt-2">{loading ? '—' : s.value}</div>
          </motion.div>
        ))}
      </div>
    </div>
  )
}


