import { useEffect, useMemo, useState } from 'react'
import { ensureAdminSession, getAdminState, commitAdminState } from '../adminStore'
import { Trash2 } from 'lucide-react'

export default function AdminBanners() {
  const [busy, setBusy] = useState(false)
  const [previewUrl, setPreviewUrl] = useState('')

  useEffect(() => {
    ensureAdminSession()
  }, [])

  const { data } = useMemo(() => getAdminState(), [busy])
  const banners = data?.banners || []

  const onImage = async (file) => {
    setBusy(true)
    try {
      const reader = new FileReader()
      const res = await new Promise((resolve, reject) => {
        reader.onload = () => resolve(reader.result)
        reader.onerror = reject
        reader.readAsDataURL(file)
      })
      const next = structuredClone(data)
      next.banners = next.banners || []
      next.banners.unshift({
        id: `bn_${Date.now()}`,
        imageUrl: String(res || ''),
        createdAt: Date.now(),
      })
      commitAdminState(next)
      setPreviewUrl(String(res || ''))
    } finally {
      setBusy(false)
    }
  }

  const del = (id) => {
    setBusy(true)
    const next = structuredClone(data)
    next.banners = (next.banners || []).filter((b) => b.id !== id)
    commitAdminState(next)
    setBusy(false)
  }

  return (
    <div className="px-0 sm:px-0">
      <div className="flex items-center justify-between mb-4 flex-col sm:flex-row gap-3">
        <div>
          <h1 className="text-2xl font-bold text-white">Banners</h1>
          <p className="text-gray-400 text-sm">Upload and manage homepage/hero banners (demo upload preview).</p>
        </div>
      </div>

      <div className="glass-dark rounded-2xl p-5 mb-4">
        <h2 className="text-lg font-bold text-white mb-2">Upload New Banner</h2>
        <p className="text-gray-400 text-sm mb-4">Images are stored in localStorage as data URLs for demo.</p>

        <label className="amazon-btn-primary amazon-btn cursor-pointer inline-flex items-center gap-2">
          Choose image
          <input type="file" accept="image/*" className="hidden" onChange={(e) => e.target.files?.[0] && onImage(e.target.files[0])} />
        </label>

        {previewUrl && <img src={previewUrl} alt="banner preview" className="mt-4 w-full max-w-xl rounded-2xl border border-white/10" />}
      </div>

      <div className="glass-dark rounded-2xl p-5">
        <h2 className="text-lg font-bold text-white mb-3">Uploaded Banners</h2>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
          {banners.map((b) => (
            <div key={b.id} className="rounded-2xl border border-white/10 bg-white/5 overflow-hidden">
              <div className="h-40 bg-black/20 flex items-center justify-center">
                {b.imageUrl ? (
                  <img src={b.imageUrl} alt="banner" className="w-full h-full object-cover" />
                ) : (
                  <div className="text-gray-500 text-sm">No image</div>
                )}
              </div>
              <div className="p-3">
                <div className="flex items-center justify-between gap-2">
                  <div className="text-gray-200 text-xs font-mono truncate">{b.id}</div>
                  <button onClick={() => del(b.id)} disabled={busy} className="amazon-btn-danger amazon-btn inline-flex items-center gap-2" type="button">
                    <Trash2 size={16} />
                  </button>
                </div>
              </div>
            </div>
          ))}

          {banners.length === 0 && (
            <div className="col-span-full text-center py-12 text-gray-400">No banners uploaded yet.</div>
          )}
        </div>
      </div>
    </div>
  )
}

