import { useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { motion } from 'framer-motion'
import { ArrowRight, Lock, Mail } from 'lucide-react'
import toast from 'react-hot-toast'

const ADMIN_EMAIL = 'kotturupraveen1234@gmail.com'
const ADMIN_PASSWORD = 'Praveen@123'

export default function AdminLoginPage() {
  const navigate = useNavigate()
  const [form, setForm] = useState({ email: '', password: '' })
  const [loading, setLoading] = useState(false)

  const submit = (e) => {
    e.preventDefault()
    setLoading(true)

    setTimeout(() => {
      const emailOk = (form.email || '').trim().toLowerCase() === ADMIN_EMAIL.toLowerCase()
      const passOk = (form.password || '') === ADMIN_PASSWORD

      if (!emailOk || !passOk) {
        toast.error('Invalid admin credentials')
        setLoading(false)
        return
      }

      const adminToken = `admin-token-${Date.now()}`
      localStorage.setItem('adminToken', adminToken)
      localStorage.setItem('role', 'admin')
      localStorage.setItem('token', '')

      toast.success('Welcome, Admin')
      navigate('/admin/dashboard')
      setLoading(false)
    }, 350)
  }

  return (
    <div className="min-h-screen flex items-center justify-center section-padding py-12">
      <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="w-full max-w-md">
        <div className="glass-dark rounded-3xl p-8 space-y-6">
          <div className="text-center space-y-2">
            <h1 className="text-2xl font-bold text-white">Admin Login</h1>
            <p className="text-gray-400">Restricted access for authorized admins</p>
          </div>

          <form onSubmit={submit} className="space-y-4">
            <div className="relative">
              <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
              <input
                type="email"
                placeholder="Admin email"
                value={form.email}
                onChange={(e) => setForm((p) => ({ ...p, email: e.target.value }))}
                className="input-field pl-12"
                required
              />
            </div>

            <div className="relative">
              <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
              <input
                type="password"
                placeholder="Admin password"
                value={form.password}
                onChange={(e) => setForm((p) => ({ ...p, password: e.target.value }))}
                className="input-field pl-12"
                required
              />
            </div>

            <button
              type="submit"
              disabled={loading}
              className="w-full btn-primary py-3 flex items-center justify-center gap-2 disabled:opacity-50"
            >
              {loading ? 'Signing in...' : 'Sign In'}
              {!loading && <ArrowRight size={18} />}
            </button>
          </form>

          <div className="text-xs text-gray-400 leading-relaxed">
            Demo-only admin auth is stored in <span className="text-gray-200 font-semibold">localStorage</span>.
          </div>
        </div>
      </motion.div>
    </div>
  )
}

