import { useMemo } from 'react'
import { Link } from 'react-router-dom'
import { Star, ShoppingCart } from 'lucide-react'
import { motion } from 'framer-motion'
import { useDispatch } from 'react-redux'
import { addToCart } from '../redux/slices/cartSlice'

export default function ProductCard({ product }) {
  const dispatch = useDispatch()

  const discountPct = Number(product.discountPercentage || 0)
  const price = product.offerPrice ?? product.price

  const fallbackImageUrl = '/placeholder-speaker.jpg'
  const imageUrlRaw = product.images?.[0]?.imageUrl || product.images?.[0]?.url
  const imageUrl = imageUrlRaw || fallbackImageUrl

  const cartPayload = useMemo(() => ({
    id: product.id,
    name: product.name,
    imageUrl,
    price,
    discountPct,
  }), [product.id, product.name, imageUrl, price, discountPct])

  const handleAddToCart = (e) => {
    e.preventDefault()
    e.stopPropagation()
    dispatch(addToCart(cartPayload))
  }

  return (
    <motion.div
      whileHover={{ y: -6 }}
      whileTap={{ scale: 0.99 }}
      transition={{ duration: 0.18 }}
      className="group block"
    >
      <Link to={`/product/${product.id}`} className="block">
        <div className="relative rounded-2xl overflow-hidden bg-dark-card border border-dark-border shadow-sm hover:shadow-lg transition-shadow duration-200">
            <div className="relative h-[120px] sm:h-[150px] md:h-[190px] overflow-hidden bg-dark-card">
              <img
                src={imageUrl}
                alt={product.name}
                loading="lazy"
                decoding="async"
                onError={(e) => {
                  // If the remote image fails, swap to local placeholder.
                  if (e.currentTarget.src !== fallbackImageUrl) {
                    e.currentTarget.src = fallbackImageUrl
                  }
                }}
                className="w-full h-full object-cover object-center bg-black/10 transition-transform duration-500 group-hover:scale-[1.04]"
              />


            {discountPct > 0 && (
              <div className="absolute top-3 left-3 px-2 py-1 bg-[#ef4444] text-white text-xs font-bold rounded-lg shadow-sm">
                -{discountPct}%
              </div>
            )}

            <div className="absolute inset-0 bg-gradient-to-t from-black/50 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300" />

            {/* Premium CTA */}
              <button
                type="button"
                onClick={handleAddToCart}
                className="absolute bottom-3 right-3 z-10 flex items-center gap-2 px-3 py-2 rounded-xl
                  bg-gradient-to-b from-[#FDCB5A] to-[#F08804]
                  text-[#111827] font-bold shadow-[0_10px_30px_rgba(240,136,4,0.35)]
                  hover:shadow-[0_14px_44px_rgba(240,136,4,0.55)] hover:translate-y-[-1px]
                  transition-all duration-200"
              >
                <ShoppingCart size={16} className="text-gray-900" />
                <span className="text-xs font-bold">Add to Cart</span>
              </button>
          </div>

              <div className="p-2.5 pt-2 pb-3 flex flex-col gap-1.5 min-h-[100px]">
            <h3 className="text-white font-semibold text-sm leading-snug line-clamp-2" title={product.name}>{product.name}</h3>


            <div className="flex items-center justify-between gap-2">
              <div className="flex items-baseline gap-2">
                <span className="text-brand-400 font-bold text-base">₹{price}</span>
                {discountPct > 0 && (
                  <span className="text-gray-500 text-xs line-through">₹{product.price}</span>
                )}
              </div>
            </div>

            {discountPct > 0 && (
              <div className="text-xs text-cyan-200/90 font-semibold">
                Save up to {discountPct}%
              </div>
            )}

            <div className="flex items-center gap-1 mt-auto">
              <Star size={14} className="text-yellow-400 fill-yellow-400" />
              <span className="text-xs text-gray-400">{product.rating}</span>
              <span className="text-xs text-gray-600">({product.reviews ?? product.totalReviews ?? 0})</span>

            </div>
          </div>
        </div>
      </Link>
    </motion.div>
  )
}


