import api from './api'

const productService = {
  // Backend endpoints (context-path: /api):
  //   GET /api/products
  //   POST /api/products
  //   PUT /api/products/{id}
  //   DELETE /api/products/{id}
  getProducts: (params) => api.get('/products', { params }).then((res) => res.data),
  getProductById: (id) => api.get(`/products/${id}`).then((res) => res.data),
  createProduct: (data) => api.post('/products', data).then((res) => res.data),
  updateProduct: (id, data) => api.put(`/products/${id}`, data).then((res) => res.data),
  deleteProduct: (id) => api.delete(`/products/${id}`).then((res) => res.data),


  // Search endpoint may or may not exist.
  // If it doesn't, UI should fall back to client-side filtering over GET /api/products.
  searchProducts: (query) => api.get('/search', { params: { q: query } }).then((res) => res.data),
}


export default productService


