import { useEffect, useMemo, useState } from 'react'
import { useParams, useNavigate } from 'react-router-dom'
import { useSelector } from 'react-redux'
import { motion, AnimatePresence } from 'framer-motion'
import { CreditCard, ChevronRight, Check, MapPin, Shield, Truck, Star } from 'lucide-react'
import toast from 'react-hot-toast'
import api from '../services/api'


const fallbackProduct = {

  id: '1',
  name: 'WebSpeak BassX Pro 40W',
  offerPrice: 2499,
  price: 2999,
  discountPercentage: 17,
  rating: 4.5,
  totalReviews: 128,
  images: [{ imageUrl: '/placeholder-speaker.jpg' }],
}

const fallbackImageUrl = '/placeholder-speaker.jpg'
const addressTypes = ['Home', 'Office']

function normalizePhone(v) {
  return (v || '').toString().replace(/\D/g, '')
}

function isValidMobile(mobile) {
  const v = normalizePhone(mobile)
  return v.length === 10
}

function isValidPincode(pincode) {
  const v = (pincode || '').toString().replace(/\D/g, '')
  return v.length === 6
}

function calcCoupon({ code, subtotal, shipping }) {
  const c = (code || '').trim().toUpperCase()
  if (!c) return { code: '', discount: 0, discountPct: 0, shippingWaived: false }

  // Example rules (UI-side):
  // SAVE10 => 10% off subtotal
  // FREESHIP => waive shipping (if any)
  if (c === 'SAVE10') {
    const discount = Math.round(subtotal * 0.1)
    return { code: c, discount, discountPct: 10, shippingWaived: false }
  }

  if (c === 'FREESHIP') {
    const shippingWaived = true
    const discount = 0
    return { code: c, discount, discountPct: 0, shippingWaived }
  }

  return { code: c, discount: 0, discountPct: 0, shippingWaived: false, invalid: true }
}

export default function BuyNowPage() {
  const { productId } = useParams()
  const navigate = useNavigate()

  const { isAuthenticated, user } = useSelector((state) => state.auth)

  const [step, setStep] = useState(1) // 1: Address, 2: Payment, 3: Confirm
  const [product, setProduct] = useState(fallbackProduct)
  const [productLoading, setProductLoading] = useState(false)


  // Address form state
  const [address, setAddress] = useState({
    fullName: '',
    mobileNumber: '',
    doorNumber: '',
    street: '',
    landmark: '',
    city: '',
    state: '',
    pincode: '',
    addressType: 'Home',
  })

  const [addressTouched, setAddressTouched] = useState({})

  const [couponCode, setCouponCode] = useState('')
  const [appliedCoupon, setAppliedCoupon] = useState('')

  // Payment method
  const [paymentMethod, setPaymentMethod] = useState(null) // 'ONLINE' | 'COD'
  const [isPlacingOrder, setIsPlacingOrder] = useState(false)

  const qty = 1
  const subtotal = useMemo(() => Number(product.offerPrice || 0) * qty, [product.offerPrice, qty])
  const baseShipping = 0 // premium UI: free shipping by default

  const couponResult = useMemo(() => {
    const result = calcCoupon({ code: appliedCoupon, subtotal, shipping: baseShipping })
    if (result?.invalid) return result
    const shipping = baseShipping
    const discount = result.discount || 0
    const shippingFinal = result.shippingWaived ? 0 : shipping
    return { ...result, shippingFinal, discountFinal: discount }
  }, [appliedCoupon, subtotal, baseShipping])

  const discount = couponResult?.discountFinal || 0
  const shipping = couponResult?.shippingFinal ?? baseShipping
  const total = Math.max(0, subtotal + shipping - discount)

  const imageUrl = product.images?.[0]?.imageUrl || fallbackImageUrl

  const addressErrors = useMemo(() => {
    const errors = {}
    if (!address.fullName?.trim()) errors.fullName = 'Full name is required'
    if (!isValidMobile(address.mobileNumber)) errors.mobileNumber = 'Valid 10-digit mobile is required'
    if (!address.doorNumber?.trim()) errors.doorNumber = 'Door/Flat number is required'
    if (!address.street?.trim()) errors.street = 'Street is required'
    if (!address.landmark?.trim()) errors.landmark = 'Landmark is required'
    if (!address.city?.trim()) errors.city = 'City is required'
    if (!address.state?.trim()) errors.state = 'State is required'
    if (!isValidPincode(address.pincode)) errors.pincode = 'Valid 6-digit pincode is required'
    if (!address.addressType) errors.addressType = 'Address type is required'
    return errors
  }, [address])

  const isAddressValid = useMemo(() => Object.keys(addressErrors).length === 0, [addressErrors])

  // Load product from backend (Admin -> MongoDB -> User)
  useEffect(() => {
    let cancelled = false
    const load = async () => {
      if (!productId) return
      setProductLoading(true)
      try {
        const res = await api.get(`/products/${productId}`)
        const p = res?.data
        if (cancelled) return

        if (p) {
          setProduct({
            id: p.id ?? p._id,
            name: p.name,
            offerPrice: p.price,
            price: p.price,
            discountPercentage: p.discountPct ?? 0,
            rating: 0,
            totalReviews: 0,
            images: p.imageUrl ? [{ imageUrl: p.imageUrl }] : [{ imageUrl: fallbackImageUrl }],
          })
          return
        }

        setProduct(fallbackProduct)
      } catch {
        if (!cancelled) setProduct(fallbackProduct)
      } finally {
        if (!cancelled) setProductLoading(false)
      }
    }

    load()
    return () => {
      cancelled = true
    }
  }, [productId])



  useEffect(() => {
    if (!isAuthenticated) return
    // Pre-fill from user if available
    if (user?.fullName && !address.fullName) {
      setAddress((prev) => ({ ...prev, fullName: user.fullName }))
    }
  }, [isAuthenticated, user, address.fullName])

  const productPremiumMeta = useMemo(() => {
    return {
      rating: product.rating ?? 0,
      reviews: product.totalReviews ?? 0,
      discountPct: Number(product.discountPercentage || 0),
    }
  }, [product])

  const canGoToPayment = isAddressValid

  const handleApplyCoupon = () => {
    const c = couponCode.trim().toUpperCase()
    if (!c) {
      toast.error('Enter a coupon code')
      return
    }

    const check = calcCoupon({ code: c, subtotal, shipping: baseShipping })
    if (check?.invalid) {
      toast.error('Invalid coupon')
      setAppliedCoupon('')
      return
    }

    setAppliedCoupon(c)
    toast.success(`Coupon ${c} applied`)
  }

  const placeOrder = async () => {
    if (!canGoToPayment) {
      toast.error('Please complete your address to continue')
      return
    }
    if (!paymentMethod) {
      toast.error('Please select payment method')
      return
    }

    setIsPlacingOrder(true)
    try {
      const payload = {
        productId: product.id,
        productName: product.name,
        imageUrl: product.images?.[0]?.imageUrl || fallbackImageUrl,
        quantity: qty,
        pricing: {
          subtotal,
          shipping,
          discount,
          total,
        },
        couponCode: appliedCoupon || null,
        address: {
          fullName: address.fullName.trim(),
          mobileNumber: normalizePhone(address.mobileNumber),
          doorNumber: address.doorNumber.trim(),
          street: address.street.trim(),
          landmark: address.landmark.trim(),
          city: address.city.trim(),
          state: address.state.trim(),
          pincode: address.pincode.toString().trim(),
          addressType: address.addressType,
        },
        payment: {
          method: paymentMethod, // 'ONLINE' | 'COD'
          status: paymentMethod === 'COD' ? 'PENDING' : 'PAID',
        },
        status: 'ORDERED',
      }

      // REAL order persistence
      const currentUser = JSON.parse(localStorage.getItem('user') || 'null')

      const orderPayload = {
        // OrderDocument fields
        userId: user?.id || currentUser?.id || null,
        userEmail: user?.email || currentUser?.email || null,
        userName: user?.fullName || currentUser?.firstName || null,

        items: [
          {
            productId: product.id,
            productName: product.name,
            imageUrl: imageUrl,
            qty,
            unitPrice: product.offerPrice,
            unitFinalPrice: product.offerPrice,
          },
        ],

        shippingAddress: {
          ...payload.address,
        },

        totals: payload.pricing,

        paymentMethod: payload.payment.method,
        paymentStatus: payload.payment.status,

        status: payload.status,

        timeline: [
          { status: 'ORDERED', at: new Date().toISOString() },
          ...(paymentMethod === 'COD'
            ? []
            : [{ status: 'PAYMENT_CONFIRMED', at: new Date().toISOString() }]),
        ],

        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
      }

      const orderRes = await api
        .post('/orders', orderPayload)
        .then((r) => r.data)

      const orderId = orderRes?.id || orderRes?._id

      navigate(`/payment/success?order_id=${encodeURIComponent(orderId || '')}`)

    } catch (e) {
      toast.error(e?.message || 'Failed to place order')
    } finally {
      setIsPlacingOrder(false)
    }
  }


  if (!isAuthenticated) {
    return (
      <div className="min-h-screen flex items-center justify-center section-padding">
        <div className="text-center space-y-4">
          <h2 className="text-2xl font-bold text-white">Please Sign In</h2>
          <p className="text-gray-400">You need to be logged in to complete your purchase</p>
          <button onClick={() => navigate('/login')} className="btn-primary">
            Sign In to Continue
          </button>
        </div>
      </div>
    )
  }

  return (
    <div className="min-h-screen section-padding py-8">
      <div className="max-w-6xl mx-auto">
        {/* Header */}
        <div className="flex items-start justify-between gap-6 mb-8">
          <div>
            <h1 className="text-3xl md:text-4xl font-extrabold text-white">Checkout</h1>
            <p className="text-gray-400 mt-2">Premium experience from cart to doorstep.</p>
          </div>
          <div className="hidden md:flex items-center gap-3 text-sm text-gray-300">
            <div className="inline-flex items-center gap-2 px-3 py-2 rounded-2xl bg-white/5 border border-white/10">
              <Truck size={16} className="text-brand-400" />
              <span>Free shipping</span>
            </div>
            <div className="inline-flex items-center gap-2 px-3 py-2 rounded-2xl bg-white/5 border border-white/10">
              <Shield size={16} className="text-brand-400" />
              <span>Secure checkout</span>
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Left - steps */}
          <div className="lg:col-span-2 space-y-6">
            {/* Steps bar */}
            <div className="glass-dark rounded-2xl p-5">
              <div className="flex items-center justify-between gap-2">
                {[{ n: 1, label: 'Choose Address' }, { n: 2, label: 'Payment' }, { n: 3, label: 'Confirm' }].map(
                  (s, i, arr) => (
                    <div key={s.n} className="flex-1 flex items-center gap-3">
                      <div className="flex items-center gap-2">
                        <div
                          className={`w-9 h-9 rounded-full flex items-center justify-center font-bold text-sm transition-all border ${
                            step === s.n
                              ? 'bg-brand-600/20 border-brand-500 text-brand-400 shadow-[0_0_24px_rgba(254,189,105,0.35)]'
                              : step > s.n
                                ? 'bg-green-500/20 border-green-500 text-green-400'
                                : 'bg-dark-border text-gray-500 border-dark-border'
                          }`}
                        >
                          {step > s.n ? <Check size={16} /> : s.n}
                        </div>
                        <div className="hidden sm:block">
                          <div className={`text-sm font-semibold ${step >= s.n ? 'text-white' : 'text-gray-500'}`}>{s.label}</div>
                          <div className="text-xs text-gray-400">Step {s.n}</div>
                        </div>
                      </div>
                      {i < arr.length - 1 && (
                        <ChevronRight className={`hidden sm:block ${step > s.n ? 'text-brand-400' : 'text-gray-700'}`} size={18} />
                      )}
                    </div>
                  )
                )}
              </div>
            </div>

            {/* Step content */}
            <AnimatePresence mode="wait">
              {step === 1 && (
                <motion.div key="addr" initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0 }}>
                  <div className="space-y-4">
                    <h2 className="text-xl md:text-2xl font-bold text-white">Address Details</h2>
                    <div className="glass-dark rounded-2xl p-6">
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <Field
                          label="Full Name"
                          value={address.fullName}
                          placeholder="e.g., John Doe"
                          error={addressTouched.fullName ? addressErrors.fullName : ''}
                          onBlur={() => setAddressTouched((p) => ({ ...p, fullName: true }))}
                          onChange={(v) => setAddress((p) => ({ ...p, fullName: v }))}
                        />

                        <Field
                          label="Mobile Number"
                          value={address.mobileNumber}
                          placeholder="10-digit mobile"
                          inputMode="numeric"
                          error={addressTouched.mobileNumber ? addressErrors.mobileNumber : ''}
                          onBlur={() => setAddressTouched((p) => ({ ...p, mobileNumber: true }))}
                          onChange={(v) => setAddress((p) => ({ ...p, mobileNumber: v }))}
                        />

                        <Field
                          label="Door / Flat Number"
                          value={address.doorNumber}
                          placeholder="Flat 12B"
                          error={addressTouched.doorNumber ? addressErrors.doorNumber : ''}
                          onBlur={() => setAddressTouched((p) => ({ ...p, doorNumber: true }))}
                          onChange={(v) => setAddress((p) => ({ ...p, doorNumber: v }))}
                        />

                        <Field
                          label="Street"
                          value={address.street}
                          placeholder="Street / Area"
                          error={addressTouched.street ? addressErrors.street : ''}
                          onBlur={() => setAddressTouched((p) => ({ ...p, street: true }))}
                          onChange={(v) => setAddress((p) => ({ ...p, street: v }))}
                        />

                        <Field
                          label="Landmark"
                          value={address.landmark}
                          placeholder="Near Metro / Building"
                          error={addressTouched.landmark ? addressErrors.landmark : ''}
                          onBlur={() => setAddressTouched((p) => ({ ...p, landmark: true }))}
                          onChange={(v) => setAddress((p) => ({ ...p, landmark: v }))}
                        />

                        <Field
                          label="City"
                          value={address.city}
                          placeholder="Bangalore"
                          error={addressTouched.city ? addressErrors.city : ''}
                          onBlur={() => setAddressTouched((p) => ({ ...p, city: true }))}
                          onChange={(v) => setAddress((p) => ({ ...p, city: v }))}
                        />

                        <Field
                          label="State"
                          value={address.state}
                          placeholder="Karnataka"
                          error={addressTouched.state ? addressErrors.state : ''}
                          onBlur={() => setAddressTouched((p) => ({ ...p, state: true }))}
                          onChange={(v) => setAddress((p) => ({ ...p, state: v }))}
                        />

                        <Field
                          label="Pincode"
                          value={address.pincode}
                          placeholder="6-digit pincode"
                          inputMode="numeric"
                          error={addressTouched.pincode ? addressErrors.pincode : ''}
                          onBlur={() => setAddressTouched((p) => ({ ...p, pincode: true }))}
                          onChange={(v) => setAddress((p) => ({ ...p, pincode: v }))}
                        />

                        <div className="md:col-span-2">
                          <label className="text-sm text-gray-300">Address Type</label>
                          <div className="mt-2 grid grid-cols-2 gap-3">
                            {addressTypes.map((t) => {
                              const selected = address.addressType === t
                              return (
                                <button
                                  key={t}
                                  type="button"
                                  onClick={() => setAddress((p) => ({ ...p, addressType: t }))}
                                  className={`p-4 rounded-xl border text-left transition-all ${
                                    selected
                                      ? 'border-brand-500 bg-brand-500/10 shadow-[0_0_26px_rgba(254,189,105,0.2)]'
                                      : 'border-dark-border bg-dark-card hover:border-white/10'
                                  }`}
                                >
                                  <div className="flex items-center gap-2">
                                    <MapPin size={18} className={selected ? 'text-brand-400' : 'text-gray-400'} />
                                    <span className="text-white font-semibold">{t}</span>
                                  </div>
                                </button>
                              )
                            })}
                          </div>
                          {addressTouched.addressType && addressErrors.addressType && (
                            <div className="mt-2 text-sm text-red-400">{addressErrors.addressType}</div>
                          )}
                        </div>
                      </div>

                      <div className="mt-6">
                        <button
                          type="button"
                          onClick={() => {
                            setAddressTouched({
                              fullName: true,
                              mobileNumber: true,
                              doorNumber: true,
                              street: true,
                              landmark: true,
                              city: true,
                              state: true,
                              pincode: true,
                              addressType: true,
                            })
                            if (!isAddressValid) {
                              toast.error('Please complete required address fields (mobile + pincode + full address)')
                              return
                            }
                            setStep(2)
                          }}
                          className={`w-full amazon-btn-primary py-4 text-lg font-bold animate-glow ${
                            !isAddressValid ? 'opacity-70 cursor-not-allowed' : ''
                          }`}
                          disabled={!canGoToPayment}
                        >
                          Continue to Payment
                        </button>

                        <div className="mt-3 text-xs text-gray-400 flex items-center gap-2">
                          <span className="h-2 w-2 rounded-full bg-brand-400 shadow-[0_0_18px_rgba(254,189,105,0.6)]" />
                          <span>
                            Validation: <span className="text-gray-200 font-semibold">Mobile + Pincode</span> and full address are mandatory.
                          </span>
                        </div>
                      </div>
                    </div>
                  </div>
                </motion.div>
              )}

              {step === 2 && (
                <motion.div key="pay" initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0 }}>
                  <div className="space-y-4">
                    <h2 className="text-xl md:text-2xl font-bold text-white">Payment Method</h2>
                    <div className="glass-dark rounded-2xl p-6">
                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                        <PaymentCard
                          title="Online Payment"
                          subtitle="UPI, Cards, NetBanking"
                          icon={<CreditCard size={22} className="text-brand-400" />}
                          selected={paymentMethod === 'ONLINE'}
                          onSelect={() => setPaymentMethod('ONLINE')}
                        />

                        <PaymentCard
                          title="Cash on Delivery (COD)"
                          subtitle="Pay at doorstep"
                          icon={<Truck size={22} className="text-brand-400" />}
                          selected={paymentMethod === 'COD'}
                          onSelect={() => setPaymentMethod('COD')}
                        />
                      </div>

                      <div className="mt-6 flex items-center gap-3">
<button type="button" onClick={() => setStep(1)} className="amazon-btn-secondary flex-1 py-3">
                          Back
                        </button>
                        <button
                          type="button"
                          onClick={() => {
                            if (!paymentMethod) {
                              toast.error('Select a payment method')
                              return
                            }
                            setStep(3)
                          }}
className={`amazon-btn-primary flex-1 py-3 text-lg font-bold ${paymentMethod ? 'animate-glow' : 'opacity-70 cursor-not-allowed'}`}
                          disabled={!paymentMethod}
                        >
                          Continue to Confirm
                        </button>
                      </div>
                    </div>
                  </div>
                </motion.div>
              )}

              {step === 3 && (
                <motion.div key="confirm" initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0 }}>
                  <div className="space-y-4">
                    <h2 className="text-xl md:text-2xl font-bold text-white">Confirm Order</h2>

                    <div className="glass-dark rounded-2xl p-6">
                      <div className="flex items-start gap-4">
                        <div className="w-24 h-24 rounded-2xl overflow-hidden bg-dark-card border border-dark-border">
                          <img
                            src={imageUrl}
                            alt={product.name}
                            onError={(e) => {
                              if (e.currentTarget.src !== fallbackImageUrl) e.currentTarget.src = fallbackImageUrl
                            }}
                            className="w-full h-full object-cover"
                            loading="lazy"
                          />
                        </div>
                        <div className="flex-1">
                          <div className="flex items-center justify-between gap-3">
                            <div>
                              <p className="text-white font-semibold">{product.name}</p>
                              <p className="text-gray-400 text-sm mt-1">
                                Qty {qty} •{' '}
                                {product.discountPercentage ? (
                                  <span className="text-green-400 font-semibold">Save {product.discountPercentage}%</span>
                                ) : (
                                  <span className="text-gray-300">Premium deal</span>
                                )}
                              </p>
                              <div className="mt-2 inline-flex items-center gap-2 px-3 py-1 rounded-full bg-white/5 border border-white/10">
                                <Star size={16} className="text-yellow-400 fill-yellow-400" />
                                <span className="text-yellow-300 text-sm font-semibold">{productPremiumMeta.rating}</span>
                                <span className="text-gray-400 text-xs">({productPremiumMeta.reviews})</span>
                              </div>
                            </div>
                            <div className="text-right">
                              <div className="text-brand-400 text-2xl font-extrabold">₹{total}</div>
                              <div className="text-gray-400 text-xs mt-1">Total payable</div>
                            </div>
                          </div>

                          <div className="mt-5">
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                              <div className="p-4 rounded-xl bg-dark-card border border-dark-border">
                                <p className="text-gray-300 font-semibold flex items-center gap-2">
                                  <MapPin size={16} className="text-brand-400" /> Delivery Address
                                </p>
                                <p className="text-white font-medium mt-2">{address.fullName}</p>
                                <p className="text-gray-400 text-sm mt-1">
                                  {address.doorNumber}, {address.street}
                                </p>
                                <p className="text-gray-400 text-sm">
                                  {address.landmark}, {address.city}, {address.state} - {address.pincode}
                                </p>
                                <p className="text-gray-400 text-sm mt-1">Mob: {normalizePhone(address.mobileNumber)}</p>
                                <p className="text-xs text-gray-500 mt-1">Type: {address.addressType}</p>
                              </div>

                              <div className="p-4 rounded-xl bg-dark-card border border-dark-border">
                                <p className="text-gray-300 font-semibold flex items-center gap-2">
                                  <CreditCard size={16} className="text-brand-400" /> Payment
                                </p>
                                <p className="text-white font-medium mt-2">
                                  {paymentMethod === 'COD' ? 'Cash on Delivery (COD)' : 'Online Payment'}
                                </p>
                                <p className="text-gray-400 text-sm mt-1">
                                  {paymentMethod === 'COD'
                                    ? 'No online charge. Pay when your order arrives.'
                                    : 'You will be charged securely during checkout.'}
                                </p>
                              </div>
                            </div>
                          </div>
                        </div>
                      </div>

                      <div className="mt-6 flex items-center gap-3">
<button type="button" onClick={() => setStep(2)} className="amazon-btn-secondary flex-1 py-3">
                          Back
                        </button>
                        <button
                          type="button"
                          onClick={placeOrder}
                          disabled={isPlacingOrder || !paymentMethod || !canGoToPayment}
className={`amazon-btn-primary flex-1 py-3 text-lg font-bold ${
                            isPlacingOrder ? 'opacity-80 cursor-wait' : 'animate-glow'
                          }`}
                        >
                          {isPlacingOrder ? 'Placing Order…' : paymentMethod === 'COD' ? 'Place Order (COD)' : 'Place Order (Online)'}
                        </button>
                      </div>

                      <div className="mt-3 text-xs text-gray-400">
                        By placing your order, you agree to WebSpeak terms and policies.
                      </div>
                    </div>
                  </div>
                </motion.div>
              )}
            </AnimatePresence>
          </div>

          {/* Right - order summary */}
          <div className="lg:col-span-1">
            <div className="glass-dark rounded-2xl p-6 sticky top-24">
              <h3 className="font-bold text-white mb-4">Order Summary</h3>

              <div className="flex gap-4 mb-4">
                <div className="w-16 h-16 rounded-xl overflow-hidden bg-dark-card border border-dark-border">
                  <img
                    src={imageUrl}
                    alt={product.name}
                    onError={(e) => {
                      if (e.currentTarget.src !== fallbackImageUrl) e.currentTarget.src = fallbackImageUrl
                    }}
                    className="w-full h-full object-cover"
                    loading="lazy"
                  />
                </div>
                <div className="min-w-0">
                  <p className="text-white font-medium text-sm line-clamp-2">{product.name}</p>
                  <div className="mt-1 flex items-center gap-2">
                    <span className="text-brand-400 font-bold">₹{product.offerPrice}</span>
                    {product.discountPercentage ? (
                      <span className="text-gray-500 text-xs line-through">₹{product.price}</span>
                    ) : null}
                  </div>
                  {product.discountPercentage ? (
                    <div className="mt-2 text-xs text-green-400 font-semibold">Save {product.discountPercentage}%</div>
                  ) : null}
                </div>
              </div>

              <div className="space-y-3 border-t border-dark-border pt-4">
                <div className="flex justify-between text-sm">
                  <span className="text-gray-400">Subtotal</span>
                  <span className="text-white">₹{subtotal}</span>
                </div>

                <div className="flex justify-between text-sm">
                  <span className="text-gray-400">Shipping</span>
                  <span className={shipping === 0 ? 'text-green-400 font-semibold' : 'text-gray-300'}>
                    {shipping === 0 ? 'FREE' : `₹${shipping}`}
                  </span>
                </div>

                {appliedCoupon ? (
                  <div className="flex justify-between text-sm">
                    <span className="text-gray-400">Discount ({appliedCoupon})</span>
                    <span className="text-green-400 font-semibold">-₹{discount}</span>
                  </div>
                ) : null}

                <div className="flex justify-between text-lg font-bold pt-2 border-t border-dark-border">
                  <span className="text-white">Total</span>
                  <span className="text-brand-400">₹{total}</span>
                </div>
              </div>

              {/* Coupon section (visible before confirm) */}
              {step <= 2 && (
                <div className="mt-6">
                  <h4 className="text-white font-semibold mb-3">Coupon</h4>
                  <div className="flex gap-3">
                    <input
                      value={couponCode}
                      onChange={(e) => setCouponCode(e.target.value)}
                      placeholder="Enter coupon (SAVE10 / FREESHIP)"
                      className="flex-1 px-4 py-3 rounded-xl bg-dark-card border border-dark-border text-white placeholder:text-gray-500 focus:outline-none focus:border-brand-500"
                    />
                    <button
                      type="button"
                      onClick={handleApplyCoupon}
                      className="px-4 py-3 rounded-xl bg-white/5 border border-white/10 text-white font-bold hover:bg-white/10 transition"
                    >
                      Apply
                    </button>
                  </div>
                  <div className="mt-2 text-xs text-gray-400">
                    Example coupons: <span className="text-gray-200 font-semibold">SAVE10</span>, <span className="text-gray-200 font-semibold">FREESHIP</span>
                  </div>
                </div>
              )}

              <div className="mt-6 p-4 rounded-2xl bg-white/5 border border-white/10">
                <div className="flex items-center gap-3">
                  <span className="h-2 w-2 rounded-full bg-brand-400 shadow-[0_0_16px_rgba(254,189,105,0.7)]" />
                  <p className="text-gray-300 text-sm font-medium">
                    {step === 1 ? 'Fill address to unlock payment' : step === 2 ? 'Select payment method to confirm' : 'Place order when ready'}
                  </p>
                </div>
              </div>

              {productLoading ? (
                <div className="mt-4 text-xs text-gray-400 animate-pulse">Updating product…</div>
              ) : null}
            </div>
          </div>
        </div>
      </div>
    </div>
  )
}

function Field({ label, value, placeholder, onChange, onBlur, error, inputMode }) {
  return (
    <div>
      <label className="text-sm text-gray-300">{label}</label>
      <input
        value={value}
        onChange={(e) => onChange(e.target.value)}
        onBlur={onBlur}
        placeholder={placeholder}
        inputMode={inputMode}
        className={`mt-2 w-full px-4 py-3 rounded-xl bg-dark-card border text-white placeholder:text-gray-500 focus:outline-none focus:border-brand-500 ${
          error ? 'border-red-500/70' : 'border-dark-border'
        }`}
      />
      {error ? <div className="mt-1 text-xs text-red-400">{error}</div> : null}
    </div>
  )
}

function PaymentCard({ title, subtitle, icon, selected, onSelect }) {
  return (
    <button
      type="button"
      onClick={onSelect}
      className={`p-5 rounded-2xl border text-left transition-all ${
        selected
          ? 'border-brand-500 bg-brand-500/10 shadow-[0_0_28px_rgba(254,189,105,0.25)]'
          : 'border-dark-border bg-dark-card hover:border-white/15'
      }`}
    >
      <div className="flex items-start gap-3">
        <div className="mt-0.5">{icon}</div>
        <div>
          <div className="text-white font-bold">{title}</div>
          <div className="text-gray-400 text-sm mt-1">{subtitle}</div>
        </div>
      </div>
      <div className={`mt-4 h-1.5 rounded-full ${selected ? 'bg-brand-500' : 'bg-dark-border'}`} />
    </button>
  )
}

