import { Link } from 'react-router-dom'
import { Home } from 'lucide-react'

export default function NotFoundPage() {
  return (
    <div className="min-h-screen flex items-center justify-center section-padding">
      <div className="text-center space-y-6">
        <div className="w-24 h-24 mx-auto bg-dark-card rounded-2xl flex items-center justify-center">
          <span className="text-4xl font-bold text-brand-400">404</span>
        </div>
        <div>
          <h1 className="text-2xl font-bold text-white">Page Not Found</h1>
          <p className="text-gray-400 mt-2">The page you're looking for doesn't exist</p>
        </div>
        <Link to="/" className="btn-primary inline-flex items-center gap-2">
          <Home size={18} />
          Back to Home
        </Link>
      </div>
    </div>
  )
}

