export default function SoundWaveLoader() {
  return (
    <div className="flex items-center gap-1 h-8">
      {[0, 1, 2, 3, 4].map((i) => (
        <div
          key={i}
          className="w-1 bg-gradient-to-t from-brand-500 to-neon-blue rounded-full"
          style={{ height: '100%', animationDelay: `${i * 0.1}s` }}
        />
      ))}
    </div>
  )
}

