import { useEffect } from 'react'
import { motion } from 'framer-motion'
import { Link } from 'react-router-dom'
import { ensureAdminSession, getAdminState } from '../adminStore'

export default function AdminDashboard() {
  useEffect(() => {
    ensureAdminSession()
  }, [])

  const { data } = getAdminState()
  const orders = data?.orders || []
  const products = data?.products || []
  const users = data?.users || []

  const totalRevenue = orders
    .filter((o) => o.status !== 'Cancelled')
    .reduce((acc, o) => acc + Number(o?.totals?.grandTotal || 0), 0)

  const pendingOrders = orders.filter((o) => o.status === 'Pending').length
  const deliveredOrders = orders.filter((o) => o.status === 'Delivered').length

  const money = (n) => Number(n || 0).toLocaleString('en-IN', { maximumFractionDigits: 0 })

  return (
    <div className="px-0 sm:px-0">
      <div className="flex items-center justify-between mb-4">
        <div>
          <h1 className="text-2xl font-bold text-white">Dashboard Overview</h1>
          <p className="text-gray-400 text-sm mt-1">Amazon-style admin overview with demo data.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-4">
        {[
          { label: 'Total Revenue', value: `₹${money(totalRevenue)}`, tone: 'from-brand-500/10 to-purple-500/10' },
          { label: 'Total Orders', value: `${orders.length}`, tone: 'from-blue-500/10 to-cyan-500/10' },
          { label: 'Pending Orders', value: `${pendingOrders}`, tone: 'from-orange-500/10 to-red-500/10' },
          { label: 'Delivered Orders', value: `${deliveredOrders}`, tone: 'from-green-500/10 to-emerald-500/10' },
        ].map((s) => (
          <motion.div
            key={s.label}
            initial={{ opacity: 0, y: 12 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.25 }}
            className={`glass-dark rounded-2xl p-6 bg-gradient-to-br ${s.tone}`}
          >
            <p className="text-gray-200 text-sm">{s.label}</p>
            <p className="text-2xl font-bold text-white mt-2">{s.value}</p>
          </motion.div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
        <div className="glass-dark rounded-2xl p-6 lg:col-span-2">
          <div className="flex items-center justify-between mb-4">
            <h2 className="text-lg font-bold text-white">Recent Orders</h2>
            <Link to="/admin/orders" className="text-brand-300 text-sm hover:underline">
              View all
            </Link>
          </div>

          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="text-gray-400 text-xs border-b border-white/10">
                  <th className="text-left py-3">Order ID</th>
                  <th className="text-left py-3">Customer</th>
                  <th className="text-left py-3">Amount</th>
                  <th className="text-left py-3">Status</th>
                </tr>
              </thead>
              <tbody className="text-sm">
                {[...orders]
                  .sort((a, b) => (b?.createdAt || 0) - (a?.createdAt || 0))
                  .slice(0, 6)
                  .map((o) => (
                    <tr key={o.id} className="border-b border-white/5">
                      <td className="py-3 text-white font-mono">{o.id}</td>
                      <td className="py-3 text-gray-300">{o.userEmail}</td>
                      <td className="py-3 text-white font-semibold">₹{money(o?.totals?.grandTotal)}</td>
                      <td className="py-3">
                        <span className="px-2 py-1 rounded-lg text-xs border border-white/10 bg-white/5 text-gray-200">
                          {o.status}
                        </span>
                      </td>
                    </tr>
                  ))}
              </tbody>
            </table>
          </div>
        </div>

        <div className="glass-dark rounded-2xl p-6">
          <h2 className="text-lg font-bold text-white mb-3">Admin Quick Actions</h2>
          <div className="text-gray-400 text-sm mb-4">Total registered users: {users.length} • Products: {products.length}</div>
          <div className="space-y-2">
            <Link to="/admin/products" className="amazon-btn-primary amazon-btn w-full inline-flex justify-center">
              Manage Products
            </Link>
            <Link to="/admin/users" className="amazon-btn-secondary amazon-btn w-full inline-flex justify-center">
              Manage Users
            </Link>
            <Link to="/admin/analytics" className="amazon-btn-secondary amazon-btn w-full inline-flex justify-center">
              View Analytics
            </Link>
          </div>
        </div>
      </div>
    </div>
  )
}

